/**
 * Laser move system — advance lasers along their velocity and destroy
 * those that leave the viewport.
 *
 * Each frame the system:
 *
 * 1. Checks if the game is paused — if so, skips all movement.
 * 2. For each laser entity, applies velocity: `x += vx * dt`, `y += vy * dt`.
 * 3. Checks whether the laser has moved beyond the viewport bounds plus
 *    {@link LASER_OFFSCREEN_MARGIN}. If so, destroys the entity.
 *
 * @packageDocumentation
 */

import type { World, Query, EntityId } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { FrameTime } from '@astracore/ecs';
import type { IWorld } from '@astracore/ecs';
import { Transform } from '@astracore/renderer-core';
import type { Application } from 'pixi.js';
import {
  LaserTag,
  Velocity,
  Collider,
  GameState,
} from '../components.js';
import { LASER_OFFSCREEN_MARGIN } from '../constants.js';

// ─── Pure functions (exported for testability / P6, P7) ───────────────────────

/**
 * Apply velocity to position. Returns new position.
 *
 * `{ x: x + vx * dt, y: y + vy * dt }`
 */
export function applyVelocity(
  x: number,
  y: number,
  vx: number,
  vy: number,
  dt: number,
): { x: number; y: number } {
  return {
    x: x + vx * dt,
    y: y + vy * dt,
  };
}

/**
 * Check if a position is out of viewport bounds (with margin).
 *
 * Returns `true` if `x < -margin` OR `x > viewportWidth + margin`
 * OR `y < -margin` OR `y > viewportHeight + margin`.
 */
export function isOutOfBounds(
  x: number,
  y: number,
  viewportWidth: number,
  viewportHeight: number,
  margin: number,
): boolean {
  return (
    x < -margin ||
    x > viewportWidth + margin ||
    y < -margin ||
    y > viewportHeight + margin
  );
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createLaserMoveSystem}. */
export interface LaserMoveSystemOptions {
  world: World;
  laserQ: Query<[typeof LaserTag, typeof Transform, typeof Velocity, typeof Collider]>;
  gameStateQ: Query<[typeof GameState]>;
  pixiApp: Application;
}

/**
 * Create and register the `shooter:laser-move` system.
 *
 * Removes the no-op stub registered by the gameplay scene and replaces it
 * with the real system that moves lasers along their velocity vectors and
 * destroys those that leave the viewport.
 */
export function createLaserMoveSystem(options: LaserMoveSystemOptions): void {
  const { world, laserQ, gameStateQ, pixiApp } = options;

  // Remove the no-op stub (if present) before registering the real system
  world.removeSystem('shooter:laser-move');

  // Register the real system
  world.addSystem({
    name: 'shooter:laser-move',
    phase: Phase.Update,
    order: 20,
    fn: (_w: IWorld, time: FrameTime) => {
      const dt = time.delta;

      // Read game state — skip if paused
      let paused = false;
      gameStateQ.forEach((_entity, gs) => {
        paused = gs.paused;
      });

      if (paused) {
        return;
      }

      // Viewport dimensions for bounds checking
      const viewportWidth = pixiApp.screen.width;
      const viewportHeight = pixiApp.screen.height;

      // Collect lasers to destroy (avoid modifying during iteration)
      const toDestroy: EntityId[] = [];

      laserQ.forEach((entity, _tag, transform, velocity) => {
        // Apply velocity
        const newPos = applyVelocity(
          transform.x,
          transform.y,
          velocity.vx,
          velocity.vy,
          dt,
        );
        transform.x = newPos.x;
        transform.y = newPos.y;

        // Check bounds
        if (isOutOfBounds(newPos.x, newPos.y, viewportWidth, viewportHeight, LASER_OFFSCREEN_MARGIN)) {
          toDestroy.push(entity);
        }
      });

      // Destroy out-of-bounds lasers
      for (const entity of toDestroy) {
        world.destroyEntity(entity);
      }
    },
  });
}
