/**
 * Game constants for the Space Shooter Demo.
 *
 * All speed values are in pixels per second unless otherwise noted.
 * All distance values are in pixels unless otherwise noted.
 *
 * @packageDocumentation
 */

// ─── Gameplay ─────────────────────────────────────────────────────────────────

/** Default planet health points at mission start. */
export const PLANET_HP_DEFAULT = 100;

/** Default number of player lives at mission start. */
export const PLAYER_LIVES_DEFAULT = 3;

/** Orbit radius as a fraction of the smaller viewport dimension. */
export const ORBIT_RADIUS_FACTOR = 0.25;

/** Collision radius for the player ship in pixels. */
export const SHIP_COLLIDER_RADIUS = 20;

/** Collision radius for the planet in pixels. */
export const PLANET_COLLIDER_RADIUS = 40;

/** Scale factor for the planet sprite (shrink to fit inside orbit). */
export const PLANET_SPRITE_SCALE = 0.3;

// ─── Ship orbital movement ────────────────────────────────────────────────────

/** Maximum angular velocity of the ship in radians per second. */
export const SHIP_MAX_ANGULAR_SPEED = 0.7;

/** Angular acceleration in radians per second² (how fast the ship speeds up toward cursor). */
export const SHIP_ANGULAR_ACCELERATION = 1.5;

/** Angular deceleration (friction) in radians per second² when close to target. */
export const SHIP_ANGULAR_FRICTION = 3.0;

/** Dead zone angle (radians) — ship won't orbit if crosshair angle is within this of current angle. */
export const SHIP_ORBIT_DEAD_ZONE = 0.15;

// ─── Laser ────────────────────────────────────────────────────────────────────

/** Laser travel speed in pixels per second. */
export const LASER_SPEED = 600;

/** Collision radius for laser projectiles in pixels. */
export const LASER_COLLIDER_RADIUS = 5;

/** Minimum time between consecutive laser shots in seconds. */
export const FIRE_RATE_COOLDOWN = 0.2;

/** Distance beyond the viewport edge before a laser is destroyed, in pixels. */
export const LASER_OFFSCREEN_MARGIN = 50;

// ─── Asteroids ────────────────────────────────────────────────────────────────

/** Valid asteroid size categories. */
export type AsteroidSize = 'big' | 'medium' | 'small' | 'tiny';

/** Per-size configuration for asteroid entities. */
export interface AsteroidSizeConfig {
  /** Circle collider radius in pixels. */
  colliderRadius: number;
  /** Base movement speed in pixels per second (before wave multiplier). */
  baseSpeed: number;
  /** Money awarded when destroyed by a laser. */
  pointValue: number;
  /** Damage dealt to the planet on collision. */
  damage: number;
  /** Sprite scale factor (1.0 = original asset size). */
  spriteScale: number;
}

/** Configuration per asteroid size category. */
export const ASTEROID_CONFIG: Record<AsteroidSize, AsteroidSizeConfig> = {
  big:    { colliderRadius: 55, baseSpeed: 35,  pointValue: 100, damage: 25, spriteScale: 1.8 },
  medium: { colliderRadius: 45, baseSpeed: 50,  pointValue: 50,  damage: 15, spriteScale: 1.4 },
  small:  { colliderRadius: 35, baseSpeed: 65,  pointValue: 25,  damage: 10, spriteScale: 1.1 },
  tiny:   { colliderRadius: 28, baseSpeed: 80,  pointValue: 10,  damage: 5,  spriteScale: 0.85 },
};

/** Distance beyond the viewport edge where asteroids spawn, in pixels. */
export const ASTEROID_SPAWN_MARGIN = 50;

// ─── Effects ──────────────────────────────────────────────────────────────────

/** Duration of the laser hit effect in seconds. */
export const HIT_EFFECT_DURATION = 0.2;

/** Delay before the player ship respawns after destruction, in seconds. */
export const RESPAWN_DELAY = 2.0;

// ─── Render layers (z-ordering) ───────────────────────────────────────────────

/** Z-order layer for the tiled background. */
export const LAYER_BACKGROUND = 0;

/** Z-order layer for the planet sprite. */
export const LAYER_PLANET = 10;

/** Z-order layer for asteroid sprites. */
export const LAYER_ASTEROID = 20;

/** Z-order layer for the player ship sprite. */
export const LAYER_SHIP = 30;

/** Z-order layer for laser projectile sprites. */
export const LAYER_LASER = 40;

/** Z-order layer for laser hit effect sprites. */
export const LAYER_HIT_EFFECT = 50;

/** Z-order layer for the crosshair sprite. */
export const LAYER_CROSSHAIR = 60;

// ─── Touch input ──────────────────────────────────────────────────────────────

/** Minimum move distance to distinguish a drag from a tap, in pixels. */
export const TOUCH_DRAG_THRESHOLD = 10;

/** Minimum touch target size in CSS pixels (WCAG 2.5.5). */
export const PAUSE_BTN_MIN_SIZE = 44;
