/**
 * Orbit system — mouse-driven slow orbital drift + crosshair-facing rotation.
 *
 * The ship moves along a fixed-radius circular orbit around the planet.
 * It slowly drifts toward the crosshair's orbital angle (the angle from
 * planet center to crosshair). The drift is gentle — the ship won't race
 * around the orbit. This lets the player aim freely at asteroids anywhere
 * on screen while the ship gradually repositions.
 *
 * The ship's visual rotation always faces the crosshair for accurate aiming.
 * Orbital position and aim direction are semi-coupled: the ship drifts toward
 * the aim direction but slowly enough that you can shoot before arriving.
 *
 * @packageDocumentation
 */

import type { World, Query } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { FrameTime, IWorld } from '@astracore/ecs';
import { Transform } from '@astracore/renderer-core';
import {
  PlayerShipTag,
  PlanetTag,
  CrosshairTag,
  OrbitalBody,
  Collider,
  GameState,
} from '../components.js';
import {
  SHIP_MAX_ANGULAR_SPEED,
  SHIP_ANGULAR_ACCELERATION,
  SHIP_ANGULAR_FRICTION,
  SHIP_ORBIT_DEAD_ZONE,
} from '../constants.js';

// ─── Pure functions (exported for testability) ────────────────────────────────

/**
 * Compute the ship's position on the orbit circle.
 */
export function computeOrbitPosition(
  angle: number,
  radius: number,
  planetCX: number,
  planetCY: number,
): { x: number; y: number } {
  return {
    x: planetCX + Math.cos(angle) * radius,
    y: planetCY + Math.sin(angle) * radius,
  };
}

/**
 * Compute the ship's rotation so its 12 o'clock (upward) direction
 * points toward the crosshair from the ship's position.
 *
 * Returns `atan2(crosshairY - shipY, crosshairX - shipX) + π/2`.
 */
export function computeShipRotation(
  shipX: number,
  shipY: number,
  crosshairX: number,
  crosshairY: number,
): number {
  return Math.atan2(crosshairY - shipY, crosshairX - shipX) + Math.PI / 2;
}

/**
 * Compute the ship's rotation facing outward from the planet center.
 * Used as fallback when no crosshair is available.
 */
export function computeShipRotationOutward(angle: number): number {
  return angle + Math.PI / 2;
}

/**
 * Compute the shortest signed angular difference between two angles.
 * Returns a value in [-π, π].
 */
export function angleDifference(target: number, current: number): number {
  let diff = target - current;
  while (diff > Math.PI) diff -= 2 * Math.PI;
  while (diff < -Math.PI) diff += 2 * Math.PI;
  return diff;
}

/**
 * Update angular velocity to slowly drift toward a target angle.
 *
 * The ship accelerates gently toward the target and decelerates when close.
 * A dead zone prevents jittering when the ship is nearly at the target.
 *
 * @param currentAV - Current angular velocity (rad/s).
 * @param angleDelta - Signed angle difference to target (rad).
 * @param dt - Frame delta time (seconds).
 * @param acceleration - Angular acceleration (rad/s²).
 * @param friction - Angular friction/deceleration (rad/s²).
 * @param maxSpeed - Maximum angular speed (rad/s).
 * @param deadZone - Angle threshold below which the ship stops drifting (rad).
 * @returns New angular velocity.
 */
export function updateAngularVelocity(
  currentAV: number,
  angleDelta: number,
  dt: number,
  acceleration: number,
  friction: number,
  maxSpeed: number,
  deadZone: number,
): number {
  let av = currentAV;
  const absDelta = Math.abs(angleDelta);

  if (absDelta <= deadZone) {
    // Inside dead zone — brake to stop
    if (Math.abs(av) < friction * dt) {
      return 0;
    }
    return av - Math.sign(av) * friction * dt;
  }

  // Outside dead zone — accelerate toward target
  const direction = Math.sign(angleDelta);
  av += direction * acceleration * dt;

  // Proportional speed limit: slow down when close to target
  // This prevents overshooting — max speed scales with distance
  const proportionalMax = Math.min(maxSpeed, absDelta * 2.0);
  if (Math.abs(av) > proportionalMax) {
    av = Math.sign(av) * proportionalMax;
  }

  // Hard clamp
  if (av > maxSpeed) av = maxSpeed;
  if (av < -maxSpeed) av = -maxSpeed;

  return av;
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createOrbitSystem}. */
export interface OrbitSystemOptions {
  world: World;
  shipQ: Query<[typeof PlayerShipTag, typeof Transform, typeof OrbitalBody]>;
  planetQ: Query<[typeof PlanetTag, typeof Transform, typeof Collider]>;
  crosshairQ: Query<[typeof CrosshairTag, typeof Transform]>;
  gameStateQ: Query<[typeof GameState]>;
}

/**
 * Create and register the `shooter:orbit` system.
 *
 * The ship slowly drifts toward the crosshair's orbital angle while
 * always facing the crosshair for accurate aiming.
 */
export function createOrbitSystem(options: OrbitSystemOptions): void {
  const { world, shipQ, planetQ, crosshairQ, gameStateQ } = options;

  // Remove the no-op stub (if present)
  world.removeSystem('shooter:orbit');

  world.addSystem({
    name: 'shooter:orbit',
    phase: Phase.Update,
    order: 5,
    fn: (_w: IWorld, time: FrameTime) => {
      const dt = time.delta;

      // Skip if paused
      let paused = false;
      gameStateQ.forEach((_entity, gs) => {
        paused = gs.paused || gs.phase !== 'playing';
      });

      // Read planet center
      let planetCX = 0;
      let planetCY = 0;
      planetQ.forEach((_entity, _tag, transform) => {
        planetCX = transform.x;
        planetCY = transform.y;
      });

      // Read crosshair position
      let crosshairX = planetCX;
      let crosshairY = planetCY;
      let hasCrosshair = false;
      crosshairQ.forEach((_entity, _tag, transform) => {
        crosshairX = transform.x;
        crosshairY = transform.y;
        hasCrosshair = true;
      });

      // Compute target orbital angle (angle from planet center to crosshair)
      const targetAngle = Math.atan2(crosshairY - planetCY, crosshairX - planetCX);

      // For each ship, slowly drift toward target angle, compute position
      shipQ.forEach((_entity, _tag, transform, orbital) => {
        if (!paused && hasCrosshair) {
          const delta = angleDifference(targetAngle, orbital.angle);

          // Update angular velocity — slow drift toward crosshair angle
          orbital.angularVelocity = updateAngularVelocity(
            orbital.angularVelocity,
            delta,
            dt,
            SHIP_ANGULAR_ACCELERATION,
            SHIP_ANGULAR_FRICTION,
            SHIP_MAX_ANGULAR_SPEED,
            SHIP_ORBIT_DEAD_ZONE,
          );

          // Advance orbital angle
          orbital.angle += orbital.angularVelocity * dt;

          // Normalize angle to [-π, π]
          while (orbital.angle > Math.PI) orbital.angle -= 2 * Math.PI;
          while (orbital.angle < -Math.PI) orbital.angle += 2 * Math.PI;
        }

        // Compute position on orbit circle
        const pos = computeOrbitPosition(
          orbital.angle,
          orbital.orbitRadius,
          planetCX,
          planetCY,
        );
        transform.x = pos.x;
        transform.y = pos.y;

        // Rotate to face the crosshair (for accurate aiming)
        if (hasCrosshair) {
          transform.rotation = computeShipRotation(pos.x, pos.y, crosshairX, crosshairY);
        } else {
          transform.rotation = computeShipRotationOutward(orbital.angle);
        }
      });
    },
  });
}
