/// <reference lib="dom" />

/**
 * Gameplay scene — ECS + Pixi.js rendering.
 *
 * Manages the full gameplay lifecycle: entity spawning, system registration,
 * resize handling, and cleanup. Systems are registered as no-op stubs here
 * and replaced with real implementations in tasks 5–9.
 *
 * @packageDocumentation
 */

import type { World, Query, EntityId } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { Scene, SceneManager } from '@astracore/scene';
import { InputState } from '@astracore/input';
import type { PixiRenderer } from '@astracore/renderer-pixi';
import { Transform, Sprite, RenderLayer } from '@astracore/renderer-core';
import type { Application } from 'pixi.js';
import { TilingSprite, Assets } from 'pixi.js';
import type { MissionDefinition } from './missions/types.js';
import {
  PlayerShipTag,
  PlanetTag,
  LaserTag,
  AsteroidTag,
  CrosshairTag,
  HitEffectTag,
  GameState,
  OrbitalBody,
  Velocity,
  Collider,
} from './components.js';
import {
  ORBIT_RADIUS_FACTOR,
  PLANET_HP_DEFAULT,
  PLAYER_LIVES_DEFAULT,
  PLANET_COLLIDER_RADIUS,
  PLANET_SPRITE_SCALE,
  SHIP_COLLIDER_RADIUS,
  LAYER_BACKGROUND,
  LAYER_PLANET,
  LAYER_SHIP,
  LAYER_CROSSHAIR,
} from './constants.js';
import { createAimSystem } from './systems/aim-system.js';
import { createOrbitSystem } from './systems/orbit-system.js';
import { createShootingSystem } from './systems/shooting-system.js';
import { createLaserMoveSystem } from './systems/laser-move-system.js';
import { createAsteroidSystem } from './systems/asteroid-system.js';
import { createCollisionSystem } from './systems/collision-system.js';
import { createGameStateSystem } from './systems/game-state-system.js';
import { createEffectsSystem } from './systems/effects-system.js';
import { setupHUD, teardownHUD } from './hud.js';
import { showPauseScreen, hideOverlay } from './screens.js';
import { SpaceShooterTouchAdapter, isTouchDevice } from './touch-input-adapter.js';

// ─── Pure calculation functions (exported for testability / P1, P2) ───────────

/**
 * Compute the planet center position for a given viewport.
 *
 * The planet is always placed at the exact center of the viewport.
 */
export function computePlanetCenter(
  viewportWidth: number,
  viewportHeight: number,
): { x: number; y: number } {
  return { x: viewportWidth / 2, y: viewportHeight / 2 };
}

/**
 * Compute the orbit radius for a given viewport.
 *
 * The radius scales with the smaller viewport dimension so the orbit
 * circle fits comfortably on any screen size.
 */
export function computeOrbitRadius(
  viewportWidth: number,
  viewportHeight: number,
): number {
  return Math.min(viewportWidth, viewportHeight) * ORBIT_RADIUS_FACTOR;
}

// ─── Entity spawning functions ────────────────────────────────────────────────

/**
 * Spawn the planet entity at the viewport center.
 */
export function spawnPlanet(world: World, cx: number, cy: number): EntityId {
  const e = world.createEntity();
  world.addComponent(e, new Transform(cx, cy, 0, 0, PLANET_SPRITE_SCALE, PLANET_SPRITE_SCALE));
  world.addComponent(e, new PlanetTag());
  world.addComponent(e, new Collider(PLANET_COLLIDER_RADIUS));
  world.addComponent(e, new Sprite('planet05', 0xffffff));
  world.addComponent(e, new RenderLayer(LAYER_PLANET));
  return e;
}

/**
 * Spawn the player ship entity on the orbit circle at angle 0 (3 o'clock).
 */
export function spawnShip(
  world: World,
  cx: number,
  cy: number,
  orbitRadius: number,
): EntityId {
  const e = world.createEntity();
  world.addComponent(e, new Transform(cx + orbitRadius, cy));
  world.addComponent(e, new PlayerShipTag());
  world.addComponent(e, new OrbitalBody(0, orbitRadius));
  world.addComponent(e, new Collider(SHIP_COLLIDER_RADIUS));
  world.addComponent(e, new Sprite('playerShip', 0xffffff));
  world.addComponent(e, new RenderLayer(LAYER_SHIP));
  return e;
}

/**
 * Spawn the crosshair entity at the origin (updated each frame by the aim system).
 */
export function spawnCrosshair(world: World): EntityId {
  const e = world.createEntity();
  world.addComponent(e, new Transform(0, 0));
  world.addComponent(e, new CrosshairTag());
  world.addComponent(e, new Sprite('crosshair', 0xffffff));
  world.addComponent(e, new RenderLayer(LAYER_CROSSHAIR));
  return e;
}

/**
 * Spawn the tiled background.
 *
 * Uses Pixi.js TilingSprite directly (not ECS) because the PixiRenderer
 * only creates regular Sprites. Returns the TilingSprite for cleanup.
 */
export function createTilingBackground(
  pixiApp: Application,
): TilingSprite | null {
  const texture = Assets.get('bg_darkPurple');
  if (!texture) return null;

  const bg = new TilingSprite({
    texture,
    width: pixiApp.screen.width,
    height: pixiApp.screen.height,
  });
  bg.zIndex = LAYER_BACKGROUND;
  pixiApp.stage.addChild(bg);
  return bg;
}

/**
 * Spawn the singleton game-state entity for the given mission.
 *
 * Total asteroids is the sum of all wave counts in the mission definition.
 */
export function spawnGameState(
  world: World,
  mission: MissionDefinition,
): EntityId {
  const totalAsteroids = mission.waves.reduce((sum, w) => sum + w.count, 0);
  const e = world.createEntity();
  world.addComponent(
    e,
    new GameState(
      PLANET_HP_DEFAULT,   // planetHp
      PLANET_HP_DEFAULT,   // planetHpMax
      PLAYER_LIVES_DEFAULT, // playerLives
      0,                   // money
      totalAsteroids,      // asteroidsRemaining
      totalAsteroids,      // totalAsteroids
      0,                   // asteroidsSpawned
      false,               // paused
      0,                   // missionTime
      0,                   // respawnTimer
      0,                   // fireCooldown
      'playing',           // phase
    ),
  );
  return e;
}

// ─── GameplayScene ────────────────────────────────────────────────────────────

/**
 * Gameplay scene — ECS + Pixi.js rendering.
 *
 * Manages the full gameplay lifecycle: entity spawning, system registration,
 * resize handling, and cleanup.
 */
export class GameplayScene implements Scene {
  public readonly name = 'gameplay';

  // ── Pre-created ECS queries (public for system access) ──────────────
  public shipQ!: Query<[typeof PlayerShipTag, typeof Transform, typeof OrbitalBody]>;
  public crosshairQ!: Query<[typeof CrosshairTag, typeof Transform]>;
  public laserQ!: Query<[typeof LaserTag, typeof Transform, typeof Velocity, typeof Collider]>;
  public asteroidQ!: Query<[typeof AsteroidTag, typeof Transform, typeof Velocity, typeof Collider]>;
  public planetQ!: Query<[typeof PlanetTag, typeof Transform, typeof Collider]>;
  public gameStateQ!: Query<[typeof GameState]>;
  public hitEffectQ!: Query<[typeof HitEffectTag]>;

  // ── Viewport state ──────────────────────────────────────────────────
  private _viewportWidth = 0;
  private _viewportHeight = 0;
  private _planetCx = 0;
  private _planetCy = 0;
  private _orbitRadius = 0;

  // ── Event listener references for cleanup ───────────────────────────
  private _resizeHandler: (() => void) | null = null;
  private _keydownHandler: ((e: KeyboardEvent) => void) | null = null;
  private _aimCleanup: (() => void) | null = null;
  private _shootingCleanup: (() => void) | null = null;
  private _touchAdapter: SpaceShooterTouchAdapter | null = null;
  private _tilingBg: TilingSprite | null = null;
  private _world: World | null = null;

  public constructor(
    private readonly _pixiApp: Application,
    private readonly _inputQuery: Query<[typeof InputState]>,
    private readonly _pixiRenderer: PixiRenderer,
    private readonly _sceneManager: SceneManager,
    private readonly _getMission: () => MissionDefinition | null,
  ) {}

  // ── onLoad: create queries, register systems, set up listeners ──────

  public onLoad(world: World): void {
    // ── Pre-create all ECS queries ────────────────────────────────────
    this.shipQ = world.query({
      with: [PlayerShipTag, Transform, OrbitalBody],
    });
    this.crosshairQ = world.query({
      with: [CrosshairTag, Transform],
    });
    this.laserQ = world.query({
      with: [LaserTag, Transform, Velocity, Collider],
    });
    this.asteroidQ = world.query({
      with: [AsteroidTag, Transform, Velocity, Collider],
    });
    this.planetQ = world.query({
      with: [PlanetTag, Transform, Collider],
    });
    this.gameStateQ = world.query({
      with: [GameState],
    });
    this.hitEffectQ = world.query({
      with: [HitEffectTag],
    });

    // ── Register all systems (stubs — replaced in onEnter with real systems) ──
    // Systems are registered in onEnter because they need the mission data.
    // We register stubs here so the system names exist for the scene world.
    world.addSystem({
      name: 'shooter:aim',
      phase: Phase.Update,
      order: 0,
      fn: () => {},
    });

    world.addSystem({
      name: 'shooter:orbit',
      phase: Phase.Update,
      order: 5,
      fn: () => {},
    });

    world.addSystem({
      name: 'shooter:shooting',
      phase: Phase.Update,
      order: 10,
      fn: () => {},
    });

    world.addSystem({
      name: 'shooter:asteroid',
      phase: Phase.Update,
      order: 15,
      fn: () => {},
    });

    world.addSystem({
      name: 'shooter:laser-move',
      phase: Phase.Update,
      order: 20,
      fn: () => {},
    });

    world.addSystem({
      name: 'shooter:collision',
      phase: Phase.Update,
      order: 25,
      fn: () => {},
    });

    world.addSystem({
      name: 'shooter:game-state',
      phase: Phase.Update,
      order: 30,
      fn: () => {},
    });

    world.addSystem({
      name: 'shooter:effects',
      phase: Phase.Update,
      order: 35,
      fn: () => {},
    });

    // ── Resize handler ────────────────────────────────────────────────
    this._resizeHandler = () => {
      this._viewportWidth = window.innerWidth;
      this._viewportHeight = window.innerHeight;

      // Resize the Pixi.js renderer
      this._pixiApp.renderer.resize(
        this._viewportWidth,
        this._viewportHeight,
      );

      // Recalculate viewport-derived values
      const center = computePlanetCenter(this._viewportWidth, this._viewportHeight);
      this._planetCx = center.x;
      this._planetCy = center.y;
      this._orbitRadius = computeOrbitRadius(this._viewportWidth, this._viewportHeight);

      // Reposition planet entity
      this.planetQ.forEach((_entity, _tag, transform) => {
        transform.x = this._planetCx;
        transform.y = this._planetCy;
      });

      // Update ship orbit radius and reposition on new orbit circle
      this.shipQ.forEach((_entity, _tag, transform, orbital) => {
        orbital.orbitRadius = this._orbitRadius;
        transform.x = this._planetCx + Math.cos(orbital.angle) * this._orbitRadius;
        transform.y = this._planetCy + Math.sin(orbital.angle) * this._orbitRadius;
      });

      // Resize tiling background
      if (this._tilingBg) {
        this._tilingBg.width = this._viewportWidth;
        this._tilingBg.height = this._viewportHeight;
      }
    };
    window.addEventListener('resize', this._resizeHandler);

    // ── Escape key pause toggle ───────────────────────────────────────
    this._keydownHandler = (e: KeyboardEvent) => {
      if (e.code === 'Escape') {
        this.gameStateQ.forEach((_entity, gs) => {
          if (gs.phase !== 'playing') return;
          gs.paused = !gs.paused;
          if (gs.paused) {
            showPauseScreen(
              () => { gs.paused = false; hideOverlay(); },
              () => { this._sceneManager.transition('menu').catch(console.error); },
            );
          } else {
            hideOverlay();
          }
        });
      }
    };
    window.addEventListener('keydown', this._keydownHandler);

    // ── Touch input adapter ───────────────────────────────────────────
    if (isTouchDevice()) {
      document.body.classList.add('touch-device');

      const canvas = this._pixiApp.canvas as HTMLCanvasElement;
      this._touchAdapter = new SpaceShooterTouchAdapter({
        canvas,
        onDragMove: (screenX, screenY) => {
          // Dispatch a synthetic pointermove so the aim system picks it up
          canvas.dispatchEvent(
            new PointerEvent('pointermove', {
              clientX: screenX,
              clientY: screenY,
            }),
          );
        },
        onTap: (screenX, screenY) => {
          // Move the crosshair to the tap position first, then fire
          canvas.dispatchEvent(
            new PointerEvent('pointermove', {
              clientX: screenX,
              clientY: screenY,
            }),
          );
          canvas.dispatchEvent(
            new PointerEvent('pointerdown', {
              clientX: screenX,
              clientY: screenY,
            }),
          );
        },
      });
    }
  }

  // ── onEnter: spawn entities, set up HUD ─────────────────────────────

  public onEnter(world: World): void {
    const mission = this._getMission();
    if (mission === null) {
      console.warn('[GameplayScene] No mission selected — returning to menu');
      this._sceneManager.transition('menu').catch(console.error);
      return;
    }

    this._world = world;

    // Calculate viewport dimensions
    this._viewportWidth = window.innerWidth;
    this._viewportHeight = window.innerHeight;

    const center = computePlanetCenter(this._viewportWidth, this._viewportHeight);
    this._planetCx = center.x;
    this._planetCy = center.y;
    this._orbitRadius = computeOrbitRadius(this._viewportWidth, this._viewportHeight);

    // Spawn all entities
    spawnPlanet(world, this._planetCx, this._planetCy);
    spawnShip(world, this._planetCx, this._planetCy, this._orbitRadius);
    spawnCrosshair(world);
    spawnGameState(world, mission);

    // Create tiled background (Pixi.js TilingSprite, not ECS)
    this._tilingBg = createTilingBackground(this._pixiApp);

    // ── Wire up real systems (replace stubs) ──────────────────────────
    this._aimCleanup = createAimSystem({
      world,
      inputQuery: this._inputQuery,
      crosshairQ: this.crosshairQ,
      pixiApp: this._pixiApp,
    });

    createOrbitSystem({
      world,
      shipQ: this.shipQ,
      planetQ: this.planetQ,
      crosshairQ: this.crosshairQ,
      gameStateQ: this.gameStateQ,
    });

    this._shootingCleanup = createShootingSystem({
      world,
      inputQuery: this._inputQuery,
      shipQ: this.shipQ,
      gameStateQ: this.gameStateQ,
      pixiApp: this._pixiApp,
    });

    createAsteroidSystem({
      world,
      asteroidQ: this.asteroidQ,
      planetQ: this.planetQ,
      gameStateQ: this.gameStateQ,
      pixiApp: this._pixiApp,
      mission,
    });

    createLaserMoveSystem({
      world,
      laserQ: this.laserQ,
      gameStateQ: this.gameStateQ,
      pixiApp: this._pixiApp,
    });

    createCollisionSystem({
      world,
      laserQ: this.laserQ,
      asteroidQ: this.asteroidQ,
      planetQ: this.planetQ,
      shipQ: this.shipQ,
      gameStateQ: this.gameStateQ,
    });

    const sceneRef = this;
    createGameStateSystem({
      world,
      gameStateQ: this.gameStateQ,
      asteroidQ: this.asteroidQ,
      shipQ: this.shipQ,
      planetQ: this.planetQ,
      pixiApp: this._pixiApp,
      onRespawnShip: () => {
        spawnShip(world, sceneRef._planetCx, sceneRef._planetCy, sceneRef._orbitRadius);
      },
      onExitToMenu: () => {
        this._sceneManager.transition('menu').catch(console.error);
      },
    });

    createEffectsSystem({
      world,
      hitEffectQ: this.hitEffectQ,
      gameStateQ: this.gameStateQ,
    });

    // Set up HUD with pause button callback
    setupHUD(() => {
      // Pause button callback — same logic as Escape key
      this.gameStateQ.forEach((_entity, gs) => {
        if (gs.phase !== 'playing') return;
        gs.paused = !gs.paused;
        if (gs.paused) {
          showPauseScreen(
            () => { gs.paused = false; hideOverlay(); },
            () => { this._sceneManager.transition('menu').catch(console.error); },
          );
        } else {
          hideOverlay();
        }
      });
    });

    // Show HUD
    const hud = document.getElementById('hud');
    if (hud) {
      hud.style.display = 'block';
    }

    // Hide default cursor on canvas
    const canvas = this._pixiApp.canvas as HTMLCanvasElement;
    canvas.style.cursor = 'none';
  }

  // ── onExit: destroy entities, clean up ──────────────────────────────

  public onExit(world: World): void {
    // Destroy all entities from every query
    const destroyFromQuery = (query: Query<any[]>) => {
      const ids: EntityId[] = [];
      query.forEach((entity: EntityId) => {
        ids.push(entity);
      });
      for (const id of ids) {
        if (world.hasEntity(id)) {
          world.destroyEntity(id);
        }
      }
    };

    destroyFromQuery(this.shipQ);
    destroyFromQuery(this.crosshairQ);
    destroyFromQuery(this.laserQ);
    destroyFromQuery(this.asteroidQ);
    destroyFromQuery(this.planetQ);
    destroyFromQuery(this.gameStateQ);
    destroyFromQuery(this.hitEffectQ);

    // Flush pending destroy commands
    world.flushCommands();

    // Remove all Pixi.js stage children
    if (this._tilingBg) {
      this._tilingBg.destroy();
      this._tilingBg = null;
    }
    this._pixiApp.stage.removeChildren();

    // Clean up event listeners
    if (this._aimCleanup) {
      this._aimCleanup();
      this._aimCleanup = null;
    }
    if (this._shootingCleanup) {
      this._shootingCleanup();
      this._shootingCleanup = null;
    }
    if (this._touchAdapter) {
      this._touchAdapter.destroy();
      this._touchAdapter = null;
      document.body.classList.remove('touch-device');
    }
    if (this._resizeHandler) {
      window.removeEventListener('resize', this._resizeHandler);
      this._resizeHandler = null;
    }
    if (this._keydownHandler) {
      window.removeEventListener('keydown', this._keydownHandler);
      this._keydownHandler = null;
    }

    // Show cursor
    const canvas = this._pixiApp.canvas as HTMLCanvasElement;
    canvas.style.cursor = '';

    // Tear down HUD and hide overlays
    teardownHUD();
    hideOverlay();

    // Hide HUD container
    const hud = document.getElementById('hud');
    if (hud) {
      hud.style.display = 'none';
    }
  }

  // ── onUnload: final cleanup ─────────────────────────────────────────

  public onUnload(_world: World): void {
    // Clean up any remaining event listeners (defensive)
    if (this._resizeHandler) {
      window.removeEventListener('resize', this._resizeHandler);
      this._resizeHandler = null;
    }
    if (this._keydownHandler) {
      window.removeEventListener('keydown', this._keydownHandler);
      this._keydownHandler = null;
    }
  }
}
