/**
 * HTML HUD overlay — setup, update, and teardown.
 *
 * The HUD is injected into the `#hud` div that already exists in index.html.
 * It displays planet HP (as a colored bar), player lives, money, and
 * asteroids remaining. A pause button is included for touch devices
 * (shown/hidden via the `.touch-device` CSS class on `<body>`).
 *
 * The {@link formatHUDValues} function is a pure function extracted for
 * testability (Property 14).
 *
 * @packageDocumentation
 */

// ─── Pure formatting function (exported for testability / P14) ────────────────

/**
 * Format raw game-state numbers into display strings for the HUD.
 *
 * This is a pure function with no DOM access — ideal for property-based
 * testing.
 */
export function formatHUDValues(
  planetHp: number,
  planetHpMax: number,
  playerLives: number,
  money: number,
  asteroidsRemaining: number,
): {
  hpText: string;
  hpPercent: number;
  livesText: string;
  moneyText: string;
  asteroidsText: string;
} {
  const hpPercent = planetHpMax > 0 ? Math.max(0, Math.min(100, (planetHp / planetHpMax) * 100)) : 0;

  return {
    hpText: `${Math.max(0, Math.floor(planetHp))} / ${Math.floor(planetHpMax)}`,
    hpPercent,
    livesText: `♥ ${playerLives}`,
    moneyText: `$ ${money}`,
    asteroidsText: `☄ ${asteroidsRemaining}`,
  };
}

// ─── DOM element references (module-scoped for fast updates) ──────────────────

let hpBarFill: HTMLElement | null = null;
let hpLabel: HTMLElement | null = null;
let livesEl: HTMLElement | null = null;
let moneyEl: HTMLElement | null = null;
let asteroidsEl: HTMLElement | null = null;

// ─── Setup ────────────────────────────────────────────────────────────────────

/**
 * Inject HUD HTML into the `#hud` element and wire the pause button.
 *
 * @param onPause - Callback invoked when the pause button is clicked.
 */
export function setupHUD(onPause?: () => void): void {
  const hud = document.getElementById('hud');
  if (!hud) return;

  hud.innerHTML = `
    <div class="hud-row" style="display:flex;align-items:center;gap:8px;margin-bottom:4px;">
      <span style="min-width:18px;">♡</span>
      <div class="hp-bar" style="
        flex:1;
        height:10px;
        background:rgba(255,255,255,0.15);
        border-radius:3px;
        overflow:hidden;
        min-width:80px;
      ">
        <div id="hud-hp-fill" style="
          height:100%;
          width:100%;
          background:#00ff88;
          border-radius:3px;
          transition:width 0.15s ease;
        "></div>
      </div>
      <span id="hud-hp-label" style="min-width:60px;text-align:right;font-size:0.85em;">100 / 100</span>
    </div>
    <div id="hud-lives" style="margin-bottom:2px;">♥ 3</div>
    <div id="hud-money" style="margin-bottom:2px;">$ 0</div>
    <div id="hud-asteroids" style="margin-bottom:2px;">☄ 0</div>
    <button class="pause-btn" id="hud-pause-btn" aria-label="Pause game">☰</button>
  `;

  // Cache DOM references for fast per-frame updates
  hpBarFill = document.getElementById('hud-hp-fill');
  hpLabel = document.getElementById('hud-hp-label');
  livesEl = document.getElementById('hud-lives');
  moneyEl = document.getElementById('hud-money');
  asteroidsEl = document.getElementById('hud-asteroids');

  // Wire pause button
  const pauseBtn = document.getElementById('hud-pause-btn');
  if (pauseBtn && onPause) {
    pauseBtn.addEventListener('click', onPause);
  }
}

// ─── Update ───────────────────────────────────────────────────────────────────

/**
 * Update the HUD DOM elements to reflect the current game state.
 *
 * Reads the provided values, formats them via {@link formatHUDValues},
 * and writes to the cached DOM elements.
 */
export function updateHUD(
  planetHp: number,
  planetHpMax: number,
  playerLives: number,
  money: number,
  asteroidsRemaining: number,
): void {
  const vals = formatHUDValues(planetHp, planetHpMax, playerLives, money, asteroidsRemaining);

  if (hpBarFill) {
    hpBarFill.style.width = `${vals.hpPercent}%`;

    // Color the bar based on HP percentage
    if (vals.hpPercent > 60) {
      hpBarFill.style.background = '#00ff88';
    } else if (vals.hpPercent > 30) {
      hpBarFill.style.background = '#ffdd44';
    } else {
      hpBarFill.style.background = '#ff4444';
    }
  }

  if (hpLabel) {
    hpLabel.textContent = vals.hpText;
  }

  if (livesEl) {
    livesEl.textContent = vals.livesText;
  }

  if (moneyEl) {
    moneyEl.textContent = vals.moneyText;
  }

  if (asteroidsEl) {
    asteroidsEl.textContent = vals.asteroidsText;
  }
}

// ─── Teardown ─────────────────────────────────────────────────────────────────

/**
 * Clear the HUD HTML and release cached DOM references.
 */
export function teardownHUD(): void {
  const hud = document.getElementById('hud');
  if (hud) {
    hud.innerHTML = '';
  }

  hpBarFill = null;
  hpLabel = null;
  livesEl = null;
  moneyEl = null;
  asteroidsEl = null;
}
