/**
 * Asteroid system — spawn asteroids per mission script, move them toward
 * the planet, and destroy those that leave the viewport.
 *
 * Each frame the system:
 *
 * 1. Checks if the game is paused or not in 'playing' phase — if so, skips.
 * 2. Advances mission elapsed time by delta.
 * 3. Checks wave triggers: for each wave whose delay ≤ missionTime and not
 *    yet triggered, spawns wave.count asteroids.
 * 4. Moves each asteroid along its velocity vector.
 * 5. Destroys asteroids that move beyond the viewport bounds.
 *
 * Pure helper functions are exported for testability (P8, P9, P10).
 *
 * @packageDocumentation
 */

import type { World, Query, EntityId } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { FrameTime } from '@astracore/ecs';
import type { IWorld } from '@astracore/ecs';
import { Transform, Sprite, RenderLayer } from '@astracore/renderer-core';
import type { Application } from 'pixi.js';
import type { MissionDefinition, MissionWave } from '../missions/types.js';
import {
  AsteroidTag,
  PlanetTag,
  Velocity,
  Collider,
  GameState,
} from '../components.js';
import type { AsteroidSize } from '../constants.js';
import {
  ASTEROID_CONFIG,
  ASTEROID_SPAWN_MARGIN,
  LAYER_ASTEROID,
} from '../constants.js';
import { applyVelocity, isOutOfBounds } from './laser-move-system.js';

// ─── Meteor sprite names per size category ────────────────────────────────────

const METEOR_SPRITES: Record<AsteroidSize, string[]> = {
  big: [
    'meteorBrown_big1', 'meteorBrown_big2', 'meteorBrown_big3', 'meteorBrown_big4',
    'meteorGrey_big1', 'meteorGrey_big2', 'meteorGrey_big3', 'meteorGrey_big4',
  ],
  medium: [
    'meteorBrown_med1', 'meteorBrown_med3',
    'meteorGrey_med1', 'meteorGrey_med2',
  ],
  small: [
    'meteorBrown_small1', 'meteorBrown_small2',
    'meteorGrey_small1', 'meteorGrey_small2',
  ],
  tiny: [
    'meteorBrown_tiny1', 'meteorBrown_tiny2',
    'meteorGrey_tiny1', 'meteorGrey_tiny2',
  ],
};

// ─── Pure functions (exported for testability / P8, P9, P10) ──────────────────

/**
 * Determine which waves should be triggered at the given elapsed time.
 *
 * Returns the indices of waves whose `delay` ≤ `elapsedTime` and that
 * have not already been triggered.
 */
export function getTriggeredWaves(
  waves: MissionWave[],
  elapsedTime: number,
  alreadyTriggered: boolean[],
): number[] {
  const result: number[] = [];
  for (let i = 0; i < waves.length; i++) {
    if (!alreadyTriggered[i] && elapsedTime >= waves[i].delay) {
      result.push(i);
    }
  }
  return result;
}

/**
 * Compute a random spawn position along the viewport edge.
 *
 * @param viewportWidth  - Width of the viewport in pixels.
 * @param viewportHeight - Height of the viewport in pixels.
 * @param margin         - Distance beyond the viewport edge to spawn at.
 * @param edge           - Which edge to spawn from, or 'any' for random.
 * @param random         - A 0–1 random number generator for testability.
 * @returns The spawn position `{ x, y }`.
 */
export function computeSpawnPosition(
  viewportWidth: number,
  viewportHeight: number,
  margin: number,
  edge: 'top' | 'bottom' | 'left' | 'right' | 'any',
  random: () => number,
): { x: number; y: number } {
  let resolvedEdge = edge;
  if (resolvedEdge === 'any') {
    const edges: Array<'top' | 'bottom' | 'left' | 'right'> = ['top', 'bottom', 'left', 'right'];
    resolvedEdge = edges[Math.floor(random() * edges.length)];
  }

  switch (resolvedEdge) {
    case 'top':
      return { x: random() * viewportWidth, y: -margin };
    case 'bottom':
      return { x: random() * viewportWidth, y: viewportHeight + margin };
    case 'left':
      return { x: -margin, y: random() * viewportHeight };
    case 'right':
      return { x: viewportWidth + margin, y: random() * viewportHeight };
  }
}

/**
 * Compute asteroid velocity directed toward the planet center.
 *
 * The direction is the normalized vector from the spawn position to the
 * planet center, scaled by the given speed.
 *
 * @param spawnX   - Asteroid spawn X position.
 * @param spawnY   - Asteroid spawn Y position.
 * @param planetCX - Planet center X position.
 * @param planetCY - Planet center Y position.
 * @param speed    - Desired speed in pixels per second.
 * @returns The velocity vector `{ vx, vy }`.
 */
export function computeAsteroidVelocity(
  spawnX: number,
  spawnY: number,
  planetCX: number,
  planetCY: number,
  speed: number,
): { vx: number; vy: number } {
  const dx = planetCX - spawnX;
  const dy = planetCY - spawnY;
  const dist = Math.sqrt(dx * dx + dy * dy);

  // If spawn is exactly at planet center (degenerate case), default to downward
  if (dist === 0) {
    return { vx: 0, vy: speed };
  }

  const dirX = dx / dist;
  const dirY = dy / dist;
  return {
    vx: dirX * speed,
    vy: dirY * speed,
  };
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createAsteroidSystem}. */
export interface AsteroidSystemOptions {
  world: World;
  asteroidQ: Query<[typeof AsteroidTag, typeof Transform, typeof Velocity, typeof Collider]>;
  planetQ: Query<[typeof PlanetTag, typeof Transform, typeof Collider]>;
  gameStateQ: Query<[typeof GameState]>;
  pixiApp: Application;
  mission: MissionDefinition;
}

/**
 * Create and register the `shooter:asteroid` system.
 *
 * Removes the no-op stub registered by the gameplay scene and replaces it
 * with the real system that spawns asteroids per mission script timing,
 * moves them toward the planet, and destroys those that leave the viewport.
 */
export function createAsteroidSystem(options: AsteroidSystemOptions): void {
  const { world, asteroidQ, planetQ, gameStateQ, pixiApp, mission } = options;

  // Track which waves have been triggered
  const wavesTriggered: boolean[] = new Array(mission.waves.length).fill(false);

  // Remove the no-op stub (if present) before registering the real system
  world.removeSystem('shooter:asteroid');

  // Register the real system
  world.addSystem({
    name: 'shooter:asteroid',
    phase: Phase.Update,
    order: 15,
    fn: (_w: IWorld, time: FrameTime) => {
      const dt = time.delta;

      // Read game state — skip if paused or not playing
      let paused = false;
      let phase: 'playing' | 'won' | 'lost' = 'playing';
      let gameState: GameState | null = null;

      gameStateQ.forEach((_entity, gs) => {
        paused = gs.paused;
        phase = gs.phase;
        gameState = gs;
      });

      if (paused || phase !== 'playing' || gameState === null) {
        return;
      }

      const gs = gameState as GameState;

      // Advance mission time
      gs.missionTime += dt;

      // ── Read planet center ──────────────────────────────────────────
      let planetCX = 0;
      let planetCY = 0;
      planetQ.forEach((_entity, _tag, transform) => {
        planetCX = transform.x;
        planetCY = transform.y;
      });

      // ── Check wave triggers ─────────────────────────────────────────
      const newWaves = getTriggeredWaves(mission.waves, gs.missionTime, wavesTriggered);

      for (const waveIndex of newWaves) {
        wavesTriggered[waveIndex] = true;
        const wave = mission.waves[waveIndex];

        const viewportWidth = pixiApp.screen.width;
        const viewportHeight = pixiApp.screen.height;

        for (let i = 0; i < wave.count; i++) {
          // Pick a random size from the wave's sizes array
          const size = wave.sizes[Math.floor(Math.random() * wave.sizes.length)] as AsteroidSize;
          const config = ASTEROID_CONFIG[size];

          // Pick a random sprite for this size
          const sprites = METEOR_SPRITES[size];
          const spriteName = sprites[Math.floor(Math.random() * sprites.length)];

          // Compute spawn position
          const pos = computeSpawnPosition(
            viewportWidth,
            viewportHeight,
            ASTEROID_SPAWN_MARGIN,
            wave.spawnEdge,
            Math.random,
          );

          // Compute velocity toward planet center
          const speed = config.baseSpeed * wave.speedMultiplier;
          const vel = computeAsteroidVelocity(pos.x, pos.y, planetCX, planetCY, speed);

          // Spawn asteroid entity
          const e = world.createEntity();
          world.addComponent(e, new Transform(pos.x, pos.y, 0, 0, config.spriteScale, config.spriteScale));
          world.addComponent(e, new AsteroidTag(size, config.pointValue));
          world.addComponent(e, new Velocity(vel.vx, vel.vy));
          world.addComponent(e, new Collider(config.colliderRadius));
          world.addComponent(e, new Sprite(spriteName, 0xffffff));
          world.addComponent(e, new RenderLayer(LAYER_ASTEROID));

          gs.asteroidsSpawned += 1;
        }
      }

      // ── Move asteroids and destroy off-screen ones ──────────────────
      const viewportWidth = pixiApp.screen.width;
      const viewportHeight = pixiApp.screen.height;
      const toDestroy: EntityId[] = [];

      asteroidQ.forEach((entity, _tag, transform, velocity) => {
        // Apply velocity
        const newPos = applyVelocity(
          transform.x,
          transform.y,
          velocity.vx,
          velocity.vy,
          dt,
        );
        transform.x = newPos.x;
        transform.y = newPos.y;

        // Check bounds — destroy if off-screen on the far side
        if (isOutOfBounds(newPos.x, newPos.y, viewportWidth, viewportHeight, ASTEROID_SPAWN_MARGIN)) {
          toDestroy.push(entity);
        }
      });

      // Destroy out-of-bounds asteroids and update remaining count
      for (const entity of toDestroy) {
        world.destroyEntity(entity);
        gs.asteroidsRemaining -= 1;
      }
    },
  });
}
