/// <reference lib="dom" />

/**
 * Shooting system — fire input → spawn lasers with cooldown.
 *
 * Listens for pointer-down events on the canvas (since InputState only
 * exposes evaluated action states, not raw pointer events for reliable
 * single-fire detection). Each frame the system:
 *
 * 1. Decrements the fire cooldown by delta (clamped to 0).
 * 2. If a fire event occurred this frame AND cooldown is 0 AND the ship
 *    exists, spawns a laser at the ship's position traveling in the
 *    ship's facing direction.
 * 3. Resets the cooldown to FIRE_RATE_COOLDOWN.
 *
 * @packageDocumentation
 */

import type { World, Query, EntityId } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { FrameTime } from '@astracore/ecs';
import type { IWorld } from '@astracore/ecs';
import type { InputState } from '@astracore/input';
import { Transform, Sprite, RenderLayer } from '@astracore/renderer-core';
import type { Application } from 'pixi.js';
import {
  PlayerShipTag,
  OrbitalBody,
  GameState,
  LaserTag,
  Velocity,
  Collider,
} from '../components.js';
import {
  LASER_SPEED,
  LASER_COLLIDER_RADIUS,
  FIRE_RATE_COOLDOWN,
  LAYER_LASER,
} from '../constants.js';

// ─── Pure functions (exported for testability / P5) ───────────────────────────

/**
 * Compute the laser velocity from the ship's rotation.
 *
 * The ship's rotation is `orbitAngle + π/2` (set by the orbit system so the
 * sprite's 12 o'clock points outward). The firing direction is outward from
 * the planet, which is the orbit angle itself:
 *
 *   firingAngle = shipRotation - π/2
 *   vx = cos(firingAngle) * LASER_SPEED
 *   vy = sin(firingAngle) * LASER_SPEED
 */
export function computeLaserVelocity(
  shipRotation: number,
): { vx: number; vy: number } {
  const firingAngle = shipRotation - Math.PI / 2;
  return {
    vx: Math.cos(firingAngle) * LASER_SPEED,
    vy: Math.sin(firingAngle) * LASER_SPEED,
  };
}

/**
 * Spawn a laser entity with the given position, velocity, and rotation.
 *
 * The laser sprite points up (12 o'clock), so its rotation is set to
 * `firingAngle + π/2` to align with the travel direction.
 */
export function spawnLaser(
  world: World,
  x: number,
  y: number,
  vx: number,
  vy: number,
  rotation: number,
): EntityId {
  const e = world.createEntity();
  world.addComponent(e, new Transform(x, y, 0, rotation));
  world.addComponent(e, new LaserTag());
  world.addComponent(e, new Velocity(vx, vy));
  world.addComponent(e, new Collider(LASER_COLLIDER_RADIUS));
  world.addComponent(e, new Sprite('laser', 0xffffff));
  world.addComponent(e, new RenderLayer(LAYER_LASER));
  return e;
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createShootingSystem}. */
export interface ShootingSystemOptions {
  world: World;
  inputQuery: Query<[typeof InputState]>;
  shipQ: Query<[typeof PlayerShipTag, typeof Transform, typeof OrbitalBody]>;
  gameStateQ: Query<[typeof GameState]>;
  pixiApp: Application;
}

/**
 * Create and register the `shooter:shooting` system.
 *
 * Sets up a `pointerdown` listener on the Pixi.js canvas to track fire
 * input (since InputState only exposes action states, not raw pointer
 * events for reliable single-fire detection). Registers the system with
 * the gameplay-scene world.
 *
 * @returns A cleanup function that removes the DOM listener.
 */
export function createShootingSystem(options: ShootingSystemOptions): () => void {
  const { world, shipQ, gameStateQ, pixiApp } = options;

  // ── Fire state tracked via DOM listener ─────────────────────────────
  let firePressed = false;

  const canvas = pixiApp.canvas as HTMLCanvasElement;

  const onPointerDown = (_e: PointerEvent): void => {
    firePressed = true;
  };

  canvas.addEventListener('pointerdown', onPointerDown);

  // ── Remove the no-op stub (if present) before registering the real system ─
  world.removeSystem('shooter:shooting');

  // ── Register the real system ────────────────────────────────────────
  world.addSystem({
    name: 'shooter:shooting',
    phase: Phase.Update,
    order: 10,
    fn: (_w: IWorld, time: FrameTime) => {
      const delta = time.delta;

      // Read game state
      let paused = false;
      let phase: 'playing' | 'won' | 'lost' = 'playing';
      let fireCooldown = 0;
      let gameState: GameState | null = null;

      gameStateQ.forEach((_entity, gs) => {
        paused = gs.paused;
        phase = gs.phase;
        fireCooldown = gs.fireCooldown;
        gameState = gs;
      });

      // Skip if paused or not playing
      if (paused || phase !== 'playing') {
        firePressed = false;
        return;
      }

      // Decrement fire cooldown
      if (gameState !== null) {
        fireCooldown = Math.max(0, fireCooldown - delta);
        (gameState as GameState).fireCooldown = fireCooldown;
      }

      // Check fire input
      const shouldFire = firePressed;
      firePressed = false;

      if (!shouldFire || fireCooldown > 0 || gameState === null) {
        return;
      }

      // Check if ship exists — if not (respawn pending), ignore fire
      let shipX = 0;
      let shipY = 0;
      let shipRotation = 0;
      let shipExists = false;

      shipQ.forEach((_entity, _tag, transform, _orbital) => {
        shipX = transform.x;
        shipY = transform.y;
        shipRotation = transform.rotation;
        shipExists = true;
      });

      if (!shipExists) {
        return;
      }

      // Compute laser velocity from ship rotation
      const { vx, vy } = computeLaserVelocity(shipRotation);

      // The laser sprite points up (12 o'clock), so rotation = firingAngle + π/2
      // firingAngle = shipRotation - π/2, so laserRotation = shipRotation - π/2 + π/2 = shipRotation
      const laserRotation = shipRotation;

      // Spawn the laser
      spawnLaser(world, shipX, shipY, vx, vy, laserRotation);

      // Set fire cooldown
      (gameState as GameState).fireCooldown = FIRE_RATE_COOLDOWN;
    },
  });

  // ── Return cleanup function ─────────────────────────────────────────
  return () => {
    canvas.removeEventListener('pointerdown', onPointerDown);
  };
}
