/// <reference lib="dom" />

/**
 * Touch input adapter for the Space Shooter Demo.
 *
 * Translates touch events into crosshair position updates (drag) and shoot
 * actions (tap). This is a simplified version of the rts-sandbox adapter —
 * no long-press, double-tap, or two-finger gestures are needed.
 *
 * State machine:
 *   IDLE → PENDING      (touchstart, 1 finger)
 *   PENDING → DRAGGING   (move > TOUCH_DRAG_THRESHOLD)
 *   PENDING → IDLE       (touchend → fire tap)
 *   DRAGGING → IDLE      (touchend)
 *   Any → IDLE           (all fingers lifted)
 *
 * @packageDocumentation
 */

import { TOUCH_DRAG_THRESHOLD } from './constants.js';

// ─── Touch device detection ───────────────────────────────────────────────────

/**
 * Detect whether the device supports touch input.
 *
 * Returns true if the browser reports touch capability via
 * `ontouchstart` or `navigator.maxTouchPoints`.
 */
export function isTouchDevice(): boolean {
  return 'ontouchstart' in window || navigator.maxTouchPoints > 0;
}

// ─── Gesture state machine ────────────────────────────────────────────────────

type GestureState = 'IDLE' | 'PENDING' | 'DRAGGING';

/**
 * Callback options for the SpaceShooterTouchAdapter.
 */
export interface SpaceShooterTouchOptions {
  canvas: HTMLCanvasElement;
  onTap: (screenX: number, screenY: number) => void;
  onDragMove: (screenX: number, screenY: number) => void;
}

/**
 * Touch input adapter that translates touch events into aim (drag) and
 * shoot (tap) actions for the space shooter.
 *
 * Gesture state machine:
 *   IDLE → PENDING      (touchstart, 1 finger)
 *   PENDING → DRAGGING   (move > TOUCH_DRAG_THRESHOLD)
 *   PENDING → IDLE       (touchend → fire tap)
 *   DRAGGING → IDLE      (touchend)
 *   Any → IDLE           (all fingers lifted)
 */
export class SpaceShooterTouchAdapter {
  private _state: GestureState = 'IDLE';
  private _startX = 0;
  private _startY = 0;

  // Bound handlers for cleanup
  private _onTouchStart: (e: TouchEvent) => void;
  private _onTouchMove: (e: TouchEvent) => void;
  private _onTouchEnd: (e: TouchEvent) => void;

  constructor(private readonly _options: SpaceShooterTouchOptions) {
    this._onTouchStart = this._handleTouchStart.bind(this);
    this._onTouchMove = this._handleTouchMove.bind(this);
    this._onTouchEnd = this._handleTouchEnd.bind(this);

    const canvas = _options.canvas;
    canvas.addEventListener('touchstart', this._onTouchStart, { passive: false });
    canvas.addEventListener('touchmove', this._onTouchMove, { passive: false });
    canvas.addEventListener('touchend', this._onTouchEnd, { passive: false });
    canvas.addEventListener('touchcancel', this._onTouchEnd, { passive: false });
  }

  /** Remove all event listeners. */
  destroy(): void {
    const canvas = this._options.canvas;
    canvas.removeEventListener('touchstart', this._onTouchStart);
    canvas.removeEventListener('touchmove', this._onTouchMove);
    canvas.removeEventListener('touchend', this._onTouchEnd);
    canvas.removeEventListener('touchcancel', this._onTouchEnd);
  }

  // ── Touch event handlers ──────────────────────────────────────────────

  private _handleTouchStart(e: TouchEvent): void {
    e.preventDefault();

    // Only handle single-finger start from IDLE
    if (e.touches.length === 1 && this._state === 'IDLE') {
      const touch = e.touches[0]!;
      this._startX = touch.clientX;
      this._startY = touch.clientY;
      this._state = 'PENDING';
    }
  }

  private _handleTouchMove(e: TouchEvent): void {
    e.preventDefault();

    // Only track the primary (first) touch point
    if (e.touches.length < 1) return;
    const touch = e.touches[0]!;

    if (this._state === 'PENDING') {
      const dx = touch.clientX - this._startX;
      const dy = touch.clientY - this._startY;
      if (Math.sqrt(dx * dx + dy * dy) > TOUCH_DRAG_THRESHOLD) {
        this._state = 'DRAGGING';
        this._options.onDragMove(touch.clientX, touch.clientY);
      }
    } else if (this._state === 'DRAGGING') {
      this._options.onDragMove(touch.clientX, touch.clientY);
    }
  }

  private _handleTouchEnd(e: TouchEvent): void {
    e.preventDefault();

    // If fingers are still down, ignore (use primary touch only)
    if (e.touches.length > 0) {
      return;
    }

    // All fingers lifted
    if (this._state === 'PENDING') {
      // Short touch without significant movement → tap (fire)
      this._options.onTap(this._startX, this._startY);
    }

    this._state = 'IDLE';
  }
}
