/**
 * Effects system — tick hit effect lifetimes and destroy expired effects.
 *
 * Each frame the system:
 *
 * 1. Skips if the game is paused.
 * 2. Iterates all hit effect entities and subtracts delta from their lifetime.
 * 3. Destroys any hit effect whose lifetime has reached zero or below.
 *
 * The logic is trivial (subtract + compare), so no pure functions are
 * extracted for testability.
 *
 * @packageDocumentation
 */

import type { World, Query, EntityId } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { FrameTime } from '@astracore/ecs';
import type { IWorld } from '@astracore/ecs';
import { HitEffectTag, GameState } from '../components.js';

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createEffectsSystem}. */
export interface EffectsSystemOptions {
  world: World;
  hitEffectQ: Query<[typeof HitEffectTag]>;
  gameStateQ: Query<[typeof GameState]>;
}

/**
 * Create and register the `shooter:effects` system.
 *
 * Removes the no-op stub registered by the gameplay scene and replaces it
 * with the real system that ticks hit effect lifetimes and destroys
 * expired effects.
 */
export function createEffectsSystem(options: EffectsSystemOptions): void {
  const { world, hitEffectQ, gameStateQ } = options;

  // Remove the no-op stub (if present) before registering the real system
  world.removeSystem('shooter:effects');

  // Register the real system
  world.addSystem({
    name: 'shooter:effects',
    phase: Phase.Update,
    order: 35,
    fn: (_w: IWorld, time: FrameTime) => {
      const dt = time.delta;

      // Read game state — skip if paused
      let paused = false;
      gameStateQ.forEach((_entity, gs) => {
        paused = gs.paused;
      });

      if (paused) {
        return;
      }

      // Collect expired effects (avoid modifying during iteration)
      const toDestroy: EntityId[] = [];

      hitEffectQ.forEach((entity, hitEffect) => {
        hitEffect.lifetime -= dt;
        if (hitEffect.lifetime <= 0) {
          toDestroy.push(entity);
        }
      });

      // Destroy expired hit effects
      for (const entity of toDestroy) {
        world.destroyEntity(entity);
      }
    },
  });
}
