/**
 * Screen overlays — Pause, Win, and Game Over screens.
 *
 * All screens are injected into the `#pause-overlay` div that already exists
 * in index.html. Each `show*` function injects HTML, displays the overlay,
 * and wires button handlers. {@link hideOverlay} hides the overlay and
 * clears its content.
 *
 * This module is the canonical source for all end-of-game and pause overlay
 * HTML. The game-state-system delegates to these functions instead of
 * building inline HTML.
 *
 * @packageDocumentation
 */

// ─── Shared styles ────────────────────────────────────────────────────────────

const PANEL_BASE = `
  background: rgba(11, 13, 26, 0.95);
  border-radius: 12px;
  padding: 48px 56px;
  max-width: 420px;
  width: 90%;
  text-align: center;
  font-family: 'Courier New', Courier, monospace;
  box-shadow: 0 0 40px rgba(0, 0, 0, 0.5);
`;

const HEADING_BASE = `
  margin: 0 0 16px 0;
  font-size: 2.2rem;
  font-weight: 700;
  letter-spacing: 3px;
  text-transform: uppercase;
`;

const SUBTEXT_BASE = `
  margin: 0 0 28px 0;
  font-size: 1.1rem;
  line-height: 1.6;
`;

function buttonStyle(color: string, bgAlpha: string, borderAlpha: string): string {
  return `
    background: rgba(${color}, ${bgAlpha});
    color: rgb(${color});
    border: 1px solid rgba(${color}, ${borderAlpha});
    border-radius: 6px;
    font-family: 'Courier New', Courier, monospace;
    font-size: 1rem;
    font-weight: 700;
    letter-spacing: 1px;
    padding: 12px 32px;
    cursor: pointer;
    min-width: 44px;
    min-height: 44px;
    text-transform: uppercase;
    transition: background 0.15s, border-color 0.15s;
    display: inline-block;
  `;
}

// ─── Overlay element helper ───────────────────────────────────────────────────

function getOverlay(): HTMLElement | null {
  return document.getElementById('pause-overlay');
}

// ─── Pause Screen ─────────────────────────────────────────────────────────────

/**
 * Show the pause screen overlay with Resume and Exit to Main Menu buttons.
 *
 * @param onResume - Called when the player clicks "Resume".
 * @param onExit   - Called when the player clicks "Exit to Main Menu".
 */
export function showPauseScreen(
  onResume: () => void,
  onExit: () => void,
): void {
  const overlay = getOverlay();
  if (!overlay) return;

  overlay.innerHTML = `
    <div style="
      ${PANEL_BASE}
      border: 1px solid rgba(0, 170, 255, 0.4);
      color: #a0c8e8;
    ">
      <h1 style="
        ${HEADING_BASE}
        color: #00aaff;
      ">Paused</h1>

      <div style="display: flex; flex-direction: column; gap: 14px; align-items: center;">
        <button id="pause-resume-btn" style="${buttonStyle('0, 170, 255', '0.15', '0.4')}">
          Resume
        </button>
        <button id="pause-exit-btn" style="${buttonStyle('0, 170, 255', '0.08', '0.25')}">
          Exit to Main Menu
        </button>
      </div>
    </div>
  `;

  overlay.style.display = 'flex';

  const resumeBtn = document.getElementById('pause-resume-btn');
  if (resumeBtn) {
    resumeBtn.addEventListener('click', onResume);
  }

  const exitBtn = document.getElementById('pause-exit-btn');
  if (exitBtn) {
    exitBtn.addEventListener('click', onExit);
  }
}

// ─── Win Screen ───────────────────────────────────────────────────────────────

/**
 * Show the win screen overlay with the final money total and a Main Menu button.
 *
 * @param money      - The player's final money total.
 * @param onMainMenu - Called when the player clicks "Main Menu".
 */
export function showWinScreen(
  money: number,
  onMainMenu: () => void,
): void {
  const overlay = getOverlay();
  if (!overlay) return;

  overlay.innerHTML = `
    <div style="
      ${PANEL_BASE}
      border: 1px solid rgba(0, 255, 136, 0.4);
      color: #aaffcc;
    ">
      <h1 style="
        ${HEADING_BASE}
        color: #00ff88;
      ">Mission Complete!</h1>

      <p style="
        ${SUBTEXT_BASE}
        color: #aaffcc;
      ">
        Credits earned: <strong style="color: #ffdd44;">$${money}</strong>
      </p>

      <button id="win-main-menu-btn" style="${buttonStyle('0, 255, 136', '0.15', '0.4')}">
        Main Menu
      </button>
    </div>
  `;

  overlay.style.display = 'flex';

  const mainMenuBtn = document.getElementById('win-main-menu-btn');
  if (mainMenuBtn) {
    mainMenuBtn.addEventListener('click', onMainMenu);
  }
}

// ─── Game Over Screen ─────────────────────────────────────────────────────────

/**
 * Show the game over screen overlay with the defeat reason and a Main Menu button.
 *
 * @param planetHp   - The planet's HP at the time of defeat. If ≤ 0, the
 *                     defeat reason is "planet destroyed"; otherwise "all ships lost".
 * @param onMainMenu - Called when the player clicks "Main Menu".
 */
export function showGameOverScreen(
  planetHp: number,
  onMainMenu: () => void,
): void {
  const overlay = getOverlay();
  if (!overlay) return;

  const reason =
    planetHp <= 0
      ? 'The planet was destroyed!'
      : 'All ships have been lost!';

  overlay.innerHTML = `
    <div style="
      ${PANEL_BASE}
      border: 1px solid rgba(255, 68, 68, 0.4);
      color: #ffaaaa;
    ">
      <h1 style="
        ${HEADING_BASE}
        color: #ff4444;
      ">Game Over</h1>

      <p style="
        ${SUBTEXT_BASE}
        color: #ffaaaa;
      ">
        ${reason}
      </p>

      <button id="lose-main-menu-btn" style="${buttonStyle('255, 68, 68', '0.15', '0.4')}">
        Main Menu
      </button>
    </div>
  `;

  overlay.style.display = 'flex';

  const mainMenuBtn = document.getElementById('lose-main-menu-btn');
  if (mainMenuBtn) {
    mainMenuBtn.addEventListener('click', onMainMenu);
  }
}

// ─── Hide Overlay ─────────────────────────────────────────────────────────────

/**
 * Hide the `#pause-overlay` and clear its content.
 */
export function hideOverlay(): void {
  const overlay = getOverlay();
  if (!overlay) return;

  overlay.style.display = 'none';
  overlay.innerHTML = '';
}
