/// <reference lib="dom" />

import type { World } from '@astracore/ecs';
import type { Scene } from '@astracore/scene';
import type { MissionDefinition } from './missions/types.js';
import { MISSIONS } from './missions/mission-1.js';

/**
 * Mission selection scene — HTML overlay listing available missions.
 *
 * Follows the same Scene lifecycle pattern as MenuScene:
 * - onLoad: no-op (no ECS systems needed)
 * - onEnter: inject HTML into #menu-overlay
 * - onExit: remove HTML from #menu-overlay
 * - onUnload: no-op
 */
export class MissionSelectScene implements Scene {
  public readonly name = 'mission-select';

  private _overlay: HTMLElement | null = null;

  public constructor(
    private readonly _onBack: () => void,
    private readonly _onSelectMission: (mission: MissionDefinition) => void,
  ) {}

  public onLoad(_world: World): void {
    // No ECS systems needed for mission select.
  }

  public onEnter(_world: World): void {
    const overlay = document.getElementById('menu-overlay');
    if (overlay === null) return;

    this._overlay = overlay;
    overlay.style.display = 'flex';
    overlay.innerHTML = this._buildHTML();

    // Wire up Back button
    const backBtn = overlay.querySelector<HTMLButtonElement>('#back-btn');
    if (backBtn) {
      backBtn.addEventListener('click', () => {
        this._onBack();
      });
    }

    // Wire up mission buttons
    for (const mission of MISSIONS) {
      const btn = overlay.querySelector<HTMLButtonElement>(`#mission-btn-${mission.id}`);
      if (btn) {
        btn.addEventListener('click', () => {
          this._onSelectMission(mission);
        });
      }
    }
  }

  public onExit(_world: World): void {
    if (this._overlay !== null) {
      this._overlay.innerHTML = '';
      this._overlay.style.display = 'none';
      this._overlay = null;
    }
  }

  public onUnload(_world: World): void {
    // Nothing to clean up.
  }

  private _buildHTML(): string {
    const missionItems = MISSIONS.map(
      (m) => `
        <button id="mission-btn-${m.id}" style="
          width: 100%;
          background: rgba(0, 85, 119, 0.6);
          color: #d0f0ff;
          border: 1px solid rgba(0, 204, 255, 0.3);
          border-radius: 6px;
          padding: 14px 16px;
          font-family: 'Courier New', Courier, monospace;
          font-size: 14px;
          text-align: left;
          cursor: pointer;
          transition: background 0.15s, border-color 0.15s;
        "
        onmouseover="this.style.background='rgba(0,119,170,0.7)'; this.style.borderColor='rgba(0,220,255,0.7)';"
        onmouseout="this.style.background='rgba(0,85,119,0.6)'; this.style.borderColor='rgba(0,204,255,0.3)';"
        >
          <div style="
            font-size: 16px;
            font-weight: 700;
            color: #00ccff;
            margin-bottom: 4px;
            letter-spacing: 1px;
          ">${m.name}</div>
          <div style="
            font-size: 12px;
            color: #7088b0;
            line-height: 1.4;
          ">${m.description}</div>
        </button>
      `,
    ).join('');

    return `
      <div style="
        background: rgba(11, 13, 26, 0.95);
        border: 1px solid rgba(0, 204, 255, 0.4);
        border-radius: 12px;
        padding: 48px 56px;
        max-width: 420px;
        width: 90%;
        text-align: center;
        font-family: 'Courier New', Courier, monospace;
        color: #c0d0f0;
        box-shadow: 0 0 40px rgba(0, 204, 255, 0.2);
      ">
        <h1 style="
          margin: 0 0 8px 0;
          font-size: 24px;
          font-weight: 700;
          color: #00ccff;
          letter-spacing: 3px;
          text-transform: uppercase;
        ">Select Mission</h1>

        <p style="
          margin: 0 0 28px 0;
          font-size: 13px;
          color: #7088b0;
          line-height: 1.6;
        ">Choose a mission to begin.</p>

        <div style="
          display: flex;
          flex-direction: column;
          gap: 10px;
          margin-bottom: 28px;
        ">
          ${missionItems}
        </div>

        <button id="back-btn" style="
          background: transparent;
          color: #7088b0;
          border: 1px solid rgba(112, 136, 176, 0.4);
          border-radius: 6px;
          padding: 10px 36px;
          font-family: 'Courier New', Courier, monospace;
          font-size: 14px;
          font-weight: 700;
          letter-spacing: 2px;
          cursor: pointer;
          transition: background 0.15s, color 0.15s, border-color 0.15s;
          text-transform: uppercase;
        "
        onmouseover="this.style.background='rgba(112,136,176,0.15)'; this.style.color='#c0d0f0'; this.style.borderColor='rgba(112,136,176,0.6)';"
        onmouseout="this.style.background='transparent'; this.style.color='#7088b0'; this.style.borderColor='rgba(112,136,176,0.4)';"
        >Back</button>
      </div>
    `;
  }
}
