/// <reference lib="dom" />

import { App } from '@astracore/application';
import { BrowserDeviceAdapter, DeviceService } from '@astracore/device';
import { BrowserInputAdapter, createInputPlugin, InputState } from '@astracore/input';
import { PixiRenderer } from '@astracore/renderer-pixi';
import { SceneManager, createScenePlugin } from '@astracore/scene';
import { Application, Assets, Sprite, Texture } from 'pixi.js';
import type { MissionDefinition } from './missions/types.js';
import { MenuScene } from './menu-scene.js';
import { MissionSelectScene } from './mission-select-scene.js';
import { GameplayScene } from './gameplay-scene.js';

/**
 * Shared Pixi.js Application instance.
 * Scenes access the stage through this reference.
 */
export let pixiApp: Application;

async function main(): Promise<void> {
  const canvas = document.getElementById('app-canvas') as HTMLCanvasElement | null;
  if (canvas === null) throw new Error('Canvas #app-canvas not found');

  // ── Pixi.js Application ─────────────────────────────────────────────
  pixiApp = new Application();
  const width = window.innerWidth;
  const height = window.innerHeight;

  await pixiApp.init({
    canvas,
    background: 0x0b0d1a,
    width,
    height,
    antialias: false,
    resolution: window.devicePixelRatio,
    autoDensity: true,
  });

  // ── AstraCore App ───────────────────────────────────────────────────
  const app = new App({ targetFps: 60, capacity: 4096 });

  // ── Input plugin ────────────────────────────────────────────────────
  const inputPlugin = createInputPlugin({
    adapter: new BrowserInputAdapter(window),
    bindings: [
      { action: 'fire', pointerButtons: [0] },
      { action: 'pause', keys: ['Escape'] },
      { action: 'orbitLeft', keys: ['KeyA', 'ArrowLeft'] },
      { action: 'orbitRight', keys: ['KeyD', 'ArrowRight'] },
    ],
  });
  app.addPlugin(inputPlugin);

  // Query for InputState on the app world — passed to scenes
  const inputQuery = app.world.query({ with: [InputState] });

  // ── Device service ──────────────────────────────────────────────────
  const deviceAdapter = new BrowserDeviceAdapter(document.documentElement);
  const _deviceService = new DeviceService(deviceAdapter);

  // ── Load all sprite assets (WebP format for smaller file sizes) ───
  Assets.add({ alias: 'playerShip', src: 'assets/playerShip1_green.webp' });
  Assets.add({ alias: 'laser', src: 'assets/laserRed.webp' });
  Assets.add({ alias: 'laserHit', src: 'assets/laserRedHit.webp' });
  Assets.add({ alias: 'crosshair', src: 'assets/crosshair.webp' });

  // Meteor sprites — explicitly listed to match actual asset files
  const meteorFiles = [
    'meteorBrown_big1', 'meteorBrown_big2', 'meteorBrown_big3', 'meteorBrown_big4',
    'meteorBrown_med1', 'meteorBrown_med3',
    'meteorBrown_small1', 'meteorBrown_small2',
    'meteorBrown_tiny1', 'meteorBrown_tiny2',
    'meteorGrey_big1', 'meteorGrey_big2', 'meteorGrey_big3', 'meteorGrey_big4',
    'meteorGrey_med1', 'meteorGrey_med2',
    'meteorGrey_small1', 'meteorGrey_small2',
    'meteorGrey_tiny1', 'meteorGrey_tiny2',
  ];
  const meteorAliases: string[] = [];
  for (const name of meteorFiles) {
    Assets.add({ alias: name, src: `assets/Meteors/${name}.webp` });
    meteorAliases.push(name);
  }

  // Planet sprites
  const planetAliases: string[] = [];
  for (let i = 0; i <= 9; i++) {
    const alias = `planet${String(i).padStart(2, '0')}`;
    Assets.add({ alias, src: `assets/Planets/${alias}.webp` });
    planetAliases.push(alias);
  }

  // Background sprites
  const bgAliases: string[] = [];
  for (const name of ['black', 'blue', 'darkPurple', 'purple'] as const) {
    const alias = `bg_${name}`;
    Assets.add({ alias, src: `assets/Backgrounds/${name}.webp` });
    bgAliases.push(alias);
  }

  const allAliases = [
    'playerShip', 'laser', 'laserHit', 'crosshair',
    ...meteorAliases,
    ...planetAliases,
    ...bgAliases,
  ];

  const loadedTextures = await Assets.load<Texture>(allAliases);

  // ── PixiRenderer ────────────────────────────────────────────────────
  const textureCache = new Map<string, Texture>();
  const pixiRenderer = new PixiRenderer(pixiApp, textureCache, () => new Sprite());

  // Register all loaded textures with the renderer
  for (const alias of allAliases) {
    const tex = loadedTextures[alias];
    if (tex) {
      pixiRenderer.registerTexture(alias, tex);
    }
  }

  // ── Scene Manager ───────────────────────────────────────────────────
  const sceneManager = new SceneManager({ worldCapacity: 4096 });

  // Track the selected mission for passing to GameplayScene
  let selectedMission: MissionDefinition | null = null;

  // MenuScene: on play → transition to mission-select
  const menuScene = new MenuScene(() => {
    sceneManager.transition('mission-select').catch(console.error);
  });

  // MissionSelectScene: on back → menu, on select → store mission + transition to gameplay
  const missionSelectScene = new MissionSelectScene(
    () => {
      sceneManager.transition('menu').catch(console.error);
    },
    (mission: MissionDefinition) => {
      selectedMission = mission;
      sceneManager.transition('gameplay').catch(console.error);
    },
  );

  // GameplayScene: receives pixiApp, inputQuery, pixiRenderer, sceneManager
  const gameplayScene = new GameplayScene(
    pixiApp,
    inputQuery,
    pixiRenderer,
    sceneManager,
    () => selectedMission,
  );

  sceneManager.register('menu', menuScene);
  sceneManager.register('mission-select', missionSelectScene);
  sceneManager.register('gameplay', gameplayScene);

  // ── Scene plugin with renderer for active scene world ───────────────
  app.addPlugin(createScenePlugin({
    manager: sceneManager,
    initial: 'menu',
    renderer: pixiRenderer,
  }));

  // ── Start the app ───────────────────────────────────────────────────
  app.start();
}

main().catch((err: unknown) => {
  console.error('[space-shooter] Fatal error:', err);
});
