/**
 * Game state system — check win/lose conditions, manage respawn timer,
 * and update HUD each frame.
 *
 * Each frame the system:
 *
 * 1. Skips if paused or phase !== 'playing'.
 * 2. Counts alive asteroids from asteroidQ.
 * 3. Checks if the player ship exists from shipQ.
 * 4. Calls determinePhase to check win/lose conditions.
 * 5. If phase changed to 'won' or 'lost', updates GameState.phase and
 *    shows the appropriate overlay.
 * 6. Manages respawn timer: decrements by delta, calls onRespawnShip
 *    when timer reaches 0 and lives > 0.
 * 7. Updates HUD (placeholder — implemented in task 11).
 *
 * Pure helper functions are exported for testability (P15).
 *
 * @packageDocumentation
 */

import type { World, Query } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { FrameTime } from '@astracore/ecs';
import type { IWorld } from '@astracore/ecs';
import { Transform } from '@astracore/renderer-core';
import type { Application } from 'pixi.js';
import {
  PlayerShipTag,
  PlanetTag,
  AsteroidTag,
  GameState,
  OrbitalBody,
  Velocity,
  Collider,
} from '../components.js';
import { showWinScreen, showGameOverScreen } from '../screens.js';
import { updateHUD } from '../hud.js';

// ─── Pure functions (exported for testability / P15) ──────────────────────────

/**
 * Determine the game phase based on current state.
 *
 * Logic:
 * - If currentPhase !== 'playing', return currentPhase (already decided).
 * - Check lose first (priority): if planetHp <= 0 → 'lost';
 *   if playerLives <= 0 AND !shipExists → 'lost'.
 * - Check win: if asteroidsSpawned >= totalAsteroids AND
 *   aliveAsteroidCount === 0 → 'won'.
 * - Otherwise: 'playing'.
 */
export function determinePhase(
  currentPhase: 'playing' | 'won' | 'lost',
  planetHp: number,
  playerLives: number,
  shipExists: boolean,
  asteroidsSpawned: number,
  totalAsteroids: number,
  aliveAsteroidCount: number,
): 'playing' | 'won' | 'lost' {
  // Already decided — no re-evaluation
  if (currentPhase !== 'playing') {
    return currentPhase;
  }

  // Lose conditions (checked first — lose takes priority over win)
  if (planetHp <= 0) {
    return 'lost';
  }
  if (playerLives <= 0 && !shipExists) {
    return 'lost';
  }

  // Win condition
  if (asteroidsSpawned >= totalAsteroids && aliveAsteroidCount === 0) {
    return 'won';
  }

  return 'playing';
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createGameStateSystem}. */
export interface GameStateSystemOptions {
  world: World;
  gameStateQ: Query<[typeof GameState]>;
  asteroidQ: Query<[typeof AsteroidTag, typeof Transform, typeof Velocity, typeof Collider]>;
  shipQ: Query<[typeof PlayerShipTag, typeof Transform, typeof OrbitalBody]>;
  planetQ: Query<[typeof PlanetTag, typeof Transform, typeof Collider]>;
  pixiApp: Application;
  /** Callback to spawn a new ship when the respawn timer expires. */
  onRespawnShip: () => void;
  /** Callback to exit to the main menu (used by win/lose screens). */
  onExitToMenu: () => void;
}

/**
 * Create and register the `shooter:game-state` system.
 *
 * Removes the no-op stub registered by the gameplay scene and replaces it
 * with the real system that checks win/lose conditions, manages the
 * respawn timer, and updates the HUD.
 */
export function createGameStateSystem(options: GameStateSystemOptions): void {
  const { world, gameStateQ, asteroidQ, shipQ, planetQ, onRespawnShip } = options;

  // Remove the no-op stub (if present) before registering the real system
  world.removeSystem('shooter:game-state');

  // Register the real system
  world.addSystem({
    name: 'shooter:game-state',
    phase: Phase.Update,
    order: 30,
    fn: (_w: IWorld, time: FrameTime) => {
      const dt = time.delta;

      // ── Read game state ─────────────────────────────────────────────
      let gameState: GameState | null = null;

      gameStateQ.forEach((_entity, gs) => {
        gameState = gs;
      });

      if (gameState === null) {
        return;
      }

      const gs = gameState as GameState;

      // Skip if paused
      if (gs.paused) {
        return;
      }

      // Skip phase checks if game already ended
      if (gs.phase !== 'playing') {
        return;
      }

      // ── Count alive asteroids ───────────────────────────────────────
      let aliveAsteroidCount = 0;
      asteroidQ.forEach(() => {
        aliveAsteroidCount += 1;
      });

      // ── Check if ship exists ────────────────────────────────────────
      let shipExists = false;
      shipQ.forEach(() => {
        shipExists = true;
      });

      // ── Determine phase ─────────────────────────────────────────────
      const newPhase = determinePhase(
        gs.phase,
        gs.planetHp,
        gs.playerLives,
        shipExists,
        gs.asteroidsSpawned,
        gs.totalAsteroids,
        aliveAsteroidCount,
      );

      if (newPhase !== gs.phase) {
        gs.phase = newPhase;

        // Show the appropriate screen overlay
        if (newPhase === 'won') {
          showWinScreen(gs.money, options.onExitToMenu);
        } else if (newPhase === 'lost') {
          showGameOverScreen(gs.planetHp, options.onExitToMenu);
        }

        // Phase changed to terminal state — skip respawn/HUD logic
        return;
      }

      // ── Manage respawn timer ────────────────────────────────────────
      if (gs.respawnTimer > 0) {
        gs.respawnTimer -= dt;
        if (gs.respawnTimer <= 0) {
          gs.respawnTimer = 0;
          if (gs.playerLives > 0) {
            onRespawnShip();
          }
        }
      }

      // ── Update HUD ─────────────────────────────────────────────────
      updateHUD(gs.planetHp, gs.planetHpMax, gs.playerLives, gs.money, gs.asteroidsRemaining);
    },
  });
}
