/**
 * Collision system — detect and resolve collisions between lasers,
 * asteroids, the planet, and the player ship.
 *
 * Each frame the system:
 *
 * 1. Skips if paused or phase !== 'playing'.
 * 2. Collects all laser and asteroid entities into arrays.
 * 3. Reads planet and ship positions.
 * 4. Checks laser↔asteroid pairs — destroy both, spawn hit effect, add money.
 * 5. Checks asteroid↔planet pairs — destroy asteroid, decrease planet HP.
 * 6. Checks asteroid↔ship pairs — destroy both, decrease lives, start respawn.
 * 7. Destroys all marked entities and updates asteroidsRemaining.
 *
 * Pure helper functions are exported for testability (P11, P12, P13).
 *
 * @packageDocumentation
 */

import type { World, Query, EntityId } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { FrameTime } from '@astracore/ecs';
import type { IWorld } from '@astracore/ecs';
import { Transform, Sprite, RenderLayer } from '@astracore/renderer-core';
import {
  PlayerShipTag,
  PlanetTag,
  LaserTag,
  AsteroidTag,
  HitEffectTag,
  GameState,
  OrbitalBody,
  Velocity,
  Collider,
} from '../components.js';
import type { AsteroidSize } from '../constants.js';
import {
  ASTEROID_CONFIG,
  HIT_EFFECT_DURATION,
  LAYER_HIT_EFFECT,
  SHIP_COLLIDER_RADIUS,
  RESPAWN_DELAY,
} from '../constants.js';

// ─── Pure functions (exported for testability / P11, P12, P13) ────────────────

/**
 * Check if two circles overlap.
 *
 * Uses squared distance for performance (avoids `Math.sqrt`):
 * `dx*dx + dy*dy < (r1+r2)*(r1+r2)`
 */
export function circlesOverlap(
  x1: number,
  y1: number,
  r1: number,
  x2: number,
  y2: number,
  r2: number,
): boolean {
  const dx = x2 - x1;
  const dy = y2 - y1;
  const sumR = r1 + r2;
  return dx * dx + dy * dy < sumR * sumR;
}

/**
 * Calculate damage to planet from asteroid size.
 *
 * Returns `ASTEROID_CONFIG[size].damage`.
 */
export function calculateDamage(size: AsteroidSize): number {
  return ASTEROID_CONFIG[size].damage;
}

/**
 * Calculate money earned from destroying an asteroid.
 *
 * Returns `ASTEROID_CONFIG[size].pointValue`.
 */
export function calculateMoney(size: AsteroidSize): number {
  return ASTEROID_CONFIG[size].pointValue;
}

/**
 * Spawn a laser hit effect entity at the given position.
 *
 * Creates an entity with Transform, HitEffectTag, Sprite('laserHit'),
 * and RenderLayer(LAYER_HIT_EFFECT).
 */
export function spawnHitEffect(world: World, x: number, y: number): EntityId {
  const e = world.createEntity();
  world.addComponent(e, new Transform(x, y));
  world.addComponent(e, new HitEffectTag(HIT_EFFECT_DURATION));
  world.addComponent(e, new Sprite('laserHit', 0xffffff));
  world.addComponent(e, new RenderLayer(LAYER_HIT_EFFECT));
  return e;
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createCollisionSystem}. */
export interface CollisionSystemOptions {
  world: World;
  laserQ: Query<[typeof LaserTag, typeof Transform, typeof Velocity, typeof Collider]>;
  asteroidQ: Query<[typeof AsteroidTag, typeof Transform, typeof Velocity, typeof Collider]>;
  planetQ: Query<[typeof PlanetTag, typeof Transform, typeof Collider]>;
  shipQ: Query<[typeof PlayerShipTag, typeof Transform, typeof OrbitalBody]>;
  gameStateQ: Query<[typeof GameState]>;
}

/** Collected laser data for collision checks. */
interface LaserInfo {
  entity: EntityId;
  x: number;
  y: number;
  radius: number;
}

/** Collected asteroid data for collision checks. */
interface AsteroidInfo {
  entity: EntityId;
  x: number;
  y: number;
  radius: number;
  size: AsteroidSize;
  pointValue: number;
}

/**
 * Create and register the `shooter:collision` system.
 *
 * Removes the no-op stub registered by the gameplay scene and replaces it
 * with the real system that detects and resolves collisions between
 * lasers, asteroids, the planet, and the player ship.
 */
export function createCollisionSystem(options: CollisionSystemOptions): void {
  const { world, laserQ, asteroidQ, planetQ, shipQ, gameStateQ } = options;

  // Remove the no-op stub (if present) before registering the real system
  world.removeSystem('shooter:collision');

  // Register the real system
  world.addSystem({
    name: 'shooter:collision',
    phase: Phase.Update,
    order: 25,
    fn: (_w: IWorld, _time: FrameTime) => {
      // ── Read game state — skip if paused or not playing ─────────────
      let paused = false;
      let phase: 'playing' | 'won' | 'lost' = 'playing';
      let gameState: GameState | null = null;

      gameStateQ.forEach((_entity, gs) => {
        paused = gs.paused;
        phase = gs.phase;
        gameState = gs;
      });

      if (paused || phase !== 'playing' || gameState === null) {
        return;
      }

      const gs = gameState as GameState;

      // ── Collect laser entities ──────────────────────────────────────
      const lasers: LaserInfo[] = [];
      laserQ.forEach((entity, _tag, transform, _velocity, collider) => {
        lasers.push({
          entity,
          x: transform.x,
          y: transform.y,
          radius: collider.radius,
        });
      });

      // ── Collect asteroid entities ───────────────────────────────────
      const asteroids: AsteroidInfo[] = [];
      asteroidQ.forEach((entity, tag, transform, _velocity, collider) => {
        asteroids.push({
          entity,
          x: transform.x,
          y: transform.y,
          radius: collider.radius,
          size: tag.size,
          pointValue: tag.pointValue,
        });
      });

      // ── Read planet position and radius ─────────────────────────────
      let planetEntity: EntityId | null = null;
      let planetX = 0;
      let planetY = 0;
      let planetRadius = 0;

      planetQ.forEach((entity, _tag, transform, collider) => {
        planetEntity = entity;
        planetX = transform.x;
        planetY = transform.y;
        planetRadius = collider.radius;
      });

      // ── Read ship position ──────────────────────────────────────────
      let shipEntity: EntityId | null = null;
      let shipX = 0;
      let shipY = 0;

      shipQ.forEach((entity, _tag, transform) => {
        shipEntity = entity;
        shipX = transform.x;
        shipY = transform.y;
      });

      // ── Track entities to destroy ───────────────────────────────────
      const destroyedLasers = new Set<EntityId>();
      const destroyedAsteroids = new Set<EntityId>();
      let destroyShip = false;
      let asteroidsDestroyedCount = 0;

      // ── 1. Laser ↔ Asteroid collisions ─────────────────────────────
      for (const laser of lasers) {
        if (destroyedLasers.has(laser.entity)) continue;

        for (const asteroid of asteroids) {
          if (destroyedAsteroids.has(asteroid.entity)) continue;

          if (circlesOverlap(
            laser.x, laser.y, laser.radius,
            asteroid.x, asteroid.y, asteroid.radius,
          )) {
            // Mark both for destruction
            destroyedLasers.add(laser.entity);
            destroyedAsteroids.add(asteroid.entity);
            asteroidsDestroyedCount += 1;

            // Spawn hit effect at midpoint
            const hitX = (laser.x + asteroid.x) / 2;
            const hitY = (laser.y + asteroid.y) / 2;
            spawnHitEffect(world, hitX, hitY);

            // Add money
            gs.money += calculateMoney(asteroid.size);

            // A laser can only hit one asteroid — break after first hit
            break;
          }
        }
      }

      // ── 2. Asteroid ↔ Planet collisions ─────────────────────────────
      if (planetEntity !== null) {
        for (const asteroid of asteroids) {
          if (destroyedAsteroids.has(asteroid.entity)) continue;

          if (circlesOverlap(
            asteroid.x, asteroid.y, asteroid.radius,
            planetX, planetY, planetRadius,
          )) {
            destroyedAsteroids.add(asteroid.entity);
            asteroidsDestroyedCount += 1;

            // Decrease planet HP
            gs.planetHp -= calculateDamage(asteroid.size);
          }
        }
      }

      // ── 3. Asteroid ↔ Ship collisions ──────────────────────────────
      if (shipEntity !== null) {
        for (const asteroid of asteroids) {
          if (destroyedAsteroids.has(asteroid.entity)) continue;

          if (circlesOverlap(
            asteroid.x, asteroid.y, asteroid.radius,
            shipX, shipY, SHIP_COLLIDER_RADIUS,
          )) {
            destroyedAsteroids.add(asteroid.entity);
            asteroidsDestroyedCount += 1;
            destroyShip = true;

            // Decrease player lives and start respawn timer
            gs.playerLives -= 1;
            gs.respawnTimer = RESPAWN_DELAY;

            // Only one asteroid can destroy the ship per frame
            break;
          }
        }
      }

      // ── 4. Destroy all marked entities ──────────────────────────────
      for (const entity of destroyedLasers) {
        if (world.hasEntity(entity)) {
          world.destroyEntity(entity);
        }
      }

      for (const entity of destroyedAsteroids) {
        if (world.hasEntity(entity)) {
          world.destroyEntity(entity);
        }
      }

      if (destroyShip && shipEntity !== null && world.hasEntity(shipEntity)) {
        world.destroyEntity(shipEntity);
      }

      // ── 5. Update asteroidsRemaining ────────────────────────────────
      gs.asteroidsRemaining -= asteroidsDestroyedCount;
    },
  });
}
