/**
 * Custom ECS components for the Space Shooter Demo.
 *
 * Plain data classes with no logic, following the monorepo component pattern
 * (see Transform in @astracore/renderer-core).
 *
 * Note: Transform, Sprite, RenderLayer, and Visibility are provided by
 * @astracore/renderer-core — they are NOT redefined here.
 *
 * @packageDocumentation
 */

import type { AsteroidSize } from './constants';

// ─── Orbital movement ─────────────────────────────────────────────

/** Marks an entity as orbiting the planet. Stores the current orbital angle and angular velocity. */
export class OrbitalBody {
  public constructor(
    /** Current orbital angle in radians (0 = right / 3 o'clock). */
    public angle: number = 0,
    /** Distance from the planet center in pixels. */
    public orbitRadius: number = 150,
    /** Current angular velocity in radians per second. */
    public angularVelocity: number = 0,
  ) {}
}

// ─── Projectile ───────────────────────────────────────────────────

/** Velocity vector for linear movement (lasers, asteroids). */
export class Velocity {
  public constructor(
    public vx: number = 0,
    public vy: number = 0,
  ) {}
}

// ─── Collision ────────────────────────────────────────────────────

/** Circle collider for collision detection. */
export class Collider {
  public constructor(public radius: number = 10) {}
}

// ─── Entity tags ──────────────────────────────────────────────────

/** Marker tag for the player ship entity. */
export class PlayerShipTag {}

/** Marker tag for the planet entity. */
export class PlanetTag {}

/** Marker tag for laser projectile entities. */
export class LaserTag {}

/** Marker tag for asteroid entities. */
export class AsteroidTag {
  public constructor(
    public size: AsteroidSize = 'medium',
    public pointValue: number = 50,
  ) {}
}

/** Marker tag for the crosshair entity. */
export class CrosshairTag {}

/** Marker tag for laser hit effect entities. */
export class HitEffectTag {
  public constructor(
    /** Seconds remaining before the effect is destroyed. */
    public lifetime: number = 0.2,
  ) {}
}

// ─── Game state (singleton) ───────────────────────────────────────

/** Singleton component holding all mutable game state. */
export class GameState {
  public constructor(
    public planetHp: number = 100,
    public planetHpMax: number = 100,
    public playerLives: number = 3,
    public money: number = 0,
    /** Total from mission script minus destroyed/cleared. */
    public asteroidsRemaining: number = 0,
    /** Total defined in mission script. */
    public totalAsteroids: number = 0,
    /** How many have been spawned so far. */
    public asteroidsSpawned: number = 0,
    public paused: boolean = false,
    /** Seconds elapsed since mission start. */
    public missionTime: number = 0,
    /** Seconds until ship respawn (0 = no respawn pending). */
    public respawnTimer: number = 0,
    /** Seconds until next shot allowed. */
    public fireCooldown: number = 0,
    public phase: 'playing' | 'won' | 'lost' = 'playing',
  ) {}
}
