/// <reference lib="dom" />

import type { World } from '@astracore/ecs';
import type { Scene } from '@astracore/scene';

/**
 * Main menu scene — HTML overlay with game title and "Play" button.
 *
 * Follows the same Scene lifecycle pattern as the rts-sandbox MenuScene:
 * - onLoad: no-op (no ECS systems needed)
 * - onEnter: inject HTML into #menu-overlay
 * - onExit: remove HTML from #menu-overlay
 * - onUnload: no-op
 */
export class MenuScene implements Scene {
  public readonly name = 'menu';

  private _overlay: HTMLElement | null = null;

  public constructor(private readonly _onPlay: () => void) {}

  public onLoad(_world: World): void {
    // No ECS systems needed for the menu.
  }

  public onEnter(_world: World): void {
    const overlay = document.getElementById('menu-overlay');
    if (overlay === null) return;

    this._overlay = overlay;
    overlay.style.display = 'flex';
    overlay.innerHTML = this._buildMenuHTML();

    // Wire up Play button
    const playBtn = overlay.querySelector<HTMLButtonElement>('#play-btn');
    if (playBtn) {
      playBtn.addEventListener('click', () => {
        this._onPlay();
      });
    }
  }

  public onExit(_world: World): void {
    if (this._overlay !== null) {
      this._overlay.innerHTML = '';
      this._overlay.style.display = 'none';
      this._overlay = null;
    }
  }

  public onUnload(_world: World): void {
    // Nothing to clean up.
  }

  private _buildMenuHTML(): string {
    return `
      <div style="
        background: rgba(11, 13, 26, 0.95);
        border: 1px solid rgba(0, 204, 255, 0.4);
        border-radius: 12px;
        padding: 48px 56px;
        max-width: 420px;
        width: 90%;
        text-align: center;
        font-family: 'Courier New', Courier, monospace;
        color: #c0d0f0;
        box-shadow: 0 0 40px rgba(0, 204, 255, 0.2);
      ">
        <h1 style="
          margin: 0 0 12px 0;
          font-size: 32px;
          font-weight: 700;
          color: #00ccff;
          letter-spacing: 3px;
          text-transform: uppercase;
        ">Space Shooter</h1>

        <p style="
          margin: 0 0 36px 0;
          font-size: 13px;
          color: #7088b0;
          line-height: 1.6;
        ">
          Defend the planet from incoming asteroids.<br/>
          Aim with your mouse or touch. Click or tap to fire.
        </p>

        <button id="play-btn" style="
          background: #005577;
          color: #d0f0ff;
          border: 1px solid rgba(0, 204, 255, 0.5);
          border-radius: 6px;
          padding: 14px 48px;
          font-family: 'Courier New', Courier, monospace;
          font-size: 18px;
          font-weight: 700;
          letter-spacing: 2px;
          cursor: pointer;
          transition: background 0.15s, border-color 0.15s;
          text-transform: uppercase;
        "
        onmouseover="this.style.background='#0077aa'; this.style.borderColor='rgba(0,220,255,0.7)';"
        onmouseout="this.style.background='#005577'; this.style.borderColor='rgba(0,204,255,0.5)';"
        >Play</button>
      </div>
    `;
  }
}
