/// <reference lib="dom" />

/**
 * Aim system — pointer tracking → crosshair position.
 *
 * The crosshair follows the pointer/touch position directly. The ship's
 * orbital movement is handled separately by the orbit system using keyboard
 * input (A/D keys). This system ONLY updates the crosshair position.
 *
 * @packageDocumentation
 */

import type { World, Query } from '@astracore/ecs';
import { Phase } from '@astracore/ecs';
import type { InputState } from '@astracore/input';
import { Transform } from '@astracore/renderer-core';
import type { Application } from 'pixi.js';
import {
  CrosshairTag,
} from '../components.js';

// ─── Pure function (exported for testability) ─────────────────────────────────

/**
 * Compute the angle from one point to another.
 *
 * Returns `atan2(toY - fromY, toX - fromX)`.
 */
export function computeAngleTo(
  fromX: number,
  fromY: number,
  toX: number,
  toY: number,
): number {
  return Math.atan2(toY - fromY, toX - fromX);
}

// ─── Clamp helper ─────────────────────────────────────────────────────────────

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/** Options accepted by {@link createAimSystem}. */
export interface AimSystemOptions {
  world: World;
  inputQuery: Query<[typeof InputState]>;
  crosshairQ: Query<[typeof CrosshairTag, typeof Transform]>;
  pixiApp: Application;
}

/**
 * Create and register the `shooter:aim` system.
 *
 * Sets up a `pointermove` listener on the Pixi.js canvas to track the
 * pointer position. Each frame updates the crosshair entity position.
 *
 * @returns A cleanup function that removes the DOM listener.
 */
export function createAimSystem(options: AimSystemOptions): () => void {
  const { world, crosshairQ, pixiApp } = options;

  // ── Pointer state tracked via DOM listener ──────────────────────────
  let pointerX = 0;
  let pointerY = 0;

  const canvas = pixiApp.canvas as HTMLCanvasElement;

  const onPointerMove = (e: PointerEvent): void => {
    pointerX = e.clientX;
    pointerY = e.clientY;
  };

  canvas.addEventListener('pointermove', onPointerMove);

  // ── Remove the no-op stub (if present) before registering the real system ─
  world.removeSystem('shooter:aim');

  // ── Register the real system ────────────────────────────────────────
  world.addSystem({
    name: 'shooter:aim',
    phase: Phase.Update,
    order: 0,
    fn: () => {
      // Viewport bounds for clamping
      const vw = pixiApp.screen.width;
      const vh = pixiApp.screen.height;

      // Clamp pointer to viewport
      const clampedX = clamp(pointerX, 0, vw);
      const clampedY = clamp(pointerY, 0, vh);

      // Update crosshair position
      crosshairQ.forEach((_entity, _tag, transform) => {
        transform.x = clampedX;
        transform.y = clampedY;
      });
    },
  });

  // ── Return cleanup function ─────────────────────────────────────────
  return () => {
    canvas.removeEventListener('pointermove', onPointerMove);
  };
}
